Below is a complete implementation for email/password signup and login using the **Appwrite Web SDK** (v1.x). It includes client setup, account creation, and session creation.

```javascript
// 1. Import the Appwrite SDK
import { Client, Account } from 'appwrite';

// 2. Initialize the Appwrite client
const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
  .setProject('YOUR_PROJECT_ID');              // Your project ID

// 3. Create an Account instance
const account = new Account(client);

// 4. Signup function (creates a new user account)
async function signup(email, password, name) {
  try {
    const response = await account.create(
      'unique()',   // userId – use 'unique()' to auto-generate
      email,
      password,
      name
    );
    console.log('Account created:', response);
    // Optionally, you can automatically log in after signup
    // await login(email, password);
    return response;
  } catch (error) {
    console.error('Signup error:', error.message);
    throw error;
  }
}

// 5. Login function (creates an email/password session)
async function login(email, password) {
  try {
    const response = await account.createEmailPasswordSession(
      email,
      password
    );
    console.log('Session created:', response);
    return response;
  } catch (error) {
    console.error('Login error:', error.message);
    throw error;
  }
}

// 6. Example usage
(async () => {
  try {
    // Sign up a new user
    const newUser = await signup('user@example.com', 'securePassword123', 'John Doe');
    console.log('User signed up:', newUser);

    // Log in with the same credentials
    const session = await login('user@example.com', 'securePassword123');
    console.log('User logged in:', session);
  } catch (error) {
    // Handle errors (e.g., user already exists, invalid credentials)
  }
})();
```

### Important notes:
- Replace `'YOUR_PROJECT_ID'` with your actual Appwrite project ID.
- The endpoint `https://cloud.appwrite.io/v1` is for Appwrite Cloud. For self‑hosted, use your server URL (e.g., `http://localhost/v1`).
- Use `'unique()'` as the `userId` to let Appwrite generate a unique ID automatically.
- After login, the session is stored automatically in the browser (cookie/localStorage) by the SDK. Subsequent requests will be authenticated.
- For production, never hardcode credentials; use a form or secure input.

### Additional: Check current session
```javascript
async function getCurrentSession() {
  try {
    const user = await account.get();
    console.log('Logged in user:', user);
    return user;
  } catch (error) {
    console.log('No active session:', error.message);
    return null;
  }
}
```

This code covers the core flow: client setup → account creation → session creation.

Below is an example using the **Appwrite Web SDK (v1.x)** with the **Databases service** (the current API for managing tables/collections and documents). The code creates a database, a `tasks` collection with the specified columns, and inserts one row.

```javascript
import { Client, Databases } from 'appwrite';

// 1. Initialize the client
const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
  .setProject('<PROJECT_ID>');                 // Your project ID

const databases = new Databases(client);

async function setupTasksDatabase() {
  try {
    // 2. Create a database (if it doesn't exist)
    const database = await databases.create(
      'unique()',           // Database ID (use 'unique()' for auto‑generated)
      'MyTasksDB'           // Database name
    );
    const databaseId = database.$id;
    console.log(`Database created: ${databaseId}`);

    // 3. Create a collection (table) named "tasks"
    const collection = await databases.createCollection(
      databaseId,
      'unique()',           // Collection ID
      'tasks',              // Collection name
      [                     // Permissions (read/write for any role)
        'read("any")',
        'write("any")'
      ]
    );
    const collectionId = collection.$id;
    console.log(`Collection created: ${collectionId}`);

    // 4. Create attributes (columns)
    //    Note: Attributes are created asynchronously; we wait for each to be "available"
    const titleAttr = await databases.createStringAttribute(
      databaseId,
      collectionId,
      'title',              // Attribute key
      255,                  // Max length
      true                  // Required
    );
    await waitForAttribute(databaseId, collectionId, 'title');
    console.log('Attribute "title" created');

    const completedAttr = await databases.createBooleanAttribute(
      databaseId,
      collectionId,
      'completed',
      true                  // Required
    );
    await waitForAttribute(databaseId, collectionId, 'completed');
    console.log('Attribute "completed" created');

    const dueDateAttr = await databases.createDatetimeAttribute(
      databaseId,
      collectionId,
      'dueDate',
      false                 // Not required
    );
    await waitForAttribute(databaseId, collectionId, 'dueDate');
    console.log('Attribute "dueDate" created');

    // 5. Insert a document (row)
    const document = await databases.createDocument(
      databaseId,
      collectionId,
      'unique()',           // Document ID
      {
        title: 'Buy groceries',
        completed: false,
        dueDate: '2025-03-15T10:00:00.000+00:00' // ISO 8601 format
      }
    );
    console.log('Document inserted:', document.$id);

  } catch (error) {
    console.error('Error:', error);
  }
}

// Helper: wait until an attribute is marked as "available"
async function waitForAttribute(databaseId, collectionId, attributeKey) {
  let attribute;
  do {
    await new Promise(resolve => setTimeout(resolve, 500)); // poll every 500ms
    const collection = await databases.getCollection(databaseId, collectionId);
    attribute = collection.attributes.find(attr => attr.key === attributeKey);
  } while (attribute && attribute.status !== 'available');
}

// Run the setup
setupTasksDatabase();
```

### Important notes

- **SDK version**: This code uses the **Appwrite Web SDK v1.x** (the current stable release). The `Databases` service replaces the older “Tables” API.
- **Permissions**: The example grants read/write to `any` role. Adjust according to your security requirements.
- **Attribute availability**: After creating an attribute, it may take a moment to become `available`. The helper function `waitForAttribute` polls until the attribute is ready before inserting data.
- **IDs**: Using `'unique()'` generates a unique ID automatically. You can also supply your own string.
- **Date format**: The `dueDate` attribute expects an ISO 8601 string (e.g., `'2025-03-15T10:00:00.000+00:00'`).

Replace `<PROJECT_ID>` with your actual Appwrite project ID and adjust the endpoint if you are using a self‑hosted instance.

Appwrite's database service stores data as **Documents** inside **Collections** (not rows in tables, but the concept is analogous). The `Query` class provides static methods to build filters, sorting, and pagination parameters for the `listDocuments()` method.

### 1. Setup
```javascript
import { Client, Databases, Query } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

const databases = new Databases(client);
```

### 2. Filtering
All filters are combined with **AND** logic.

```javascript
// Equality
Query.equal('status', 'active')
Query.equal('category', ['tech', 'gaming']) // Array match (OR within the array)

// Inequality
Query.notEqual('role', 'banned')

// Comparison
Query.lessThan('price', 50)
Query.greaterThan('age', 18)
Query.lessThanEqual('rating', 4.5)
Query.greaterThanEqual('stock', 1)

// Text Search (requires a fulltext index)
Query.search('title', 'laptop')

// Array Contains
Query.contains('tags', 'sale')
```

### 3. Sorting
```javascript
Query.orderAsc('name')
Query.orderDesc('createdAt')
```

### 4. Limiting
```javascript
Query.limit(25) // Max 100 per request
```

### 5. Pagination

**Offset Pagination** (simple, but less performant on large datasets):
```javascript
// Page 1
[Query.limit(10), Query.offset(0)]
// Page 2
[Query.limit(10), Query.offset(10)]
```

**Cursor Pagination** (recommended for real-time data):
```javascript
// First page
let response = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [Query.limit(10), Query.orderAsc('$id')]
);

// Next page
let nextPage = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.limit(10),
        Query.orderAsc('$id'),
        Query.cursorAfter(response.documents[response.documents.length - 1].$id)
    ]
);

// Previous page
let prevPage = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.limit(10),
        Query.orderAsc('$id'),
        Query.cursorBefore(response.documents[0].$id)
    ]
);
```

### 6. Complete Example
```javascript
async function getPublishedProducts(page = 0) {
    const queries = [
        Query.equal('status', 'published'),
        Query.greaterThan('stock', 0),
        Query.orderDesc('createdAt'),
        Query.limit(20),
        Query.offset(page * 20)
    ];

    const response = await databases.listDocuments(
        'DATABASE_ID',
        'COLLECTION_ID',
        queries
    );

    return response;
}
```

### ⚠️ Important Notes
- **Indexes are required.** You must create an index in the Appwrite Console for every attribute you filter or sort by (e.g., an index on `status` for `equal`, or a fulltext index on `title` for `search`).
- **AND logic only.** You cannot combine queries with OR in a single `listDocuments` call.
- **Cursor pagination** is more reliable than offset pagination when documents are frequently added or removed.

Here's the correct Appwrite Function in Node.js:

```javascript
module.exports = async function (req, res) {
  // req.body is automatically parsed if Content-Type is application/json
  const { name } = req.body;

  // Return a JSON response with the greeting
  res.json({ greeting: `Hello, ${name}!` });
};
```

**Key points:**
- The function signature uses `async (req, res)` as required by Appwrite.
- `req.body` contains the parsed JSON payload (Appwrite handles parsing automatically).
- `res.json()` sends a JSON response with the correct `Content-Type` header.
- The response format is `{ "greeting": "Hello, <name>!" }`.

For production, you may want to add validation:

```javascript
module.exports = async function (req, res) {
  const { name } = req.body || {};

  if (!name || typeof name !== 'string') {
    return res.json({ error: 'Missing or invalid "name" field' }, 400);
  }

  res.json({ greeting: `Hello, ${name}!` });
};
```

Below is a complete example using the **Appwrite Web SDK** to create a storage bucket, upload an image file, and generate a preview URL. The code includes permission configuration for both the bucket and the uploaded file.

```javascript
import { Client, Storage, Permission, Role, ID } from 'appwrite';

// Initialize the Appwrite client (replace with your own endpoint and project ID)
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('YOUR_PROJECT_ID');              // Your project ID

const storage = new Storage(client);

/**
 * Creates a bucket, uploads a file, and returns a preview URL.
 * @param {File} file - The image file to upload (e.g., from an <input> element)
 * @returns {Promise<string>} - The preview URL of the uploaded image
 */
async function createBucketAndUploadImage(file) {
    try {
        // 1. Create a new bucket with public read/write permissions
        const bucket = await storage.createBucket(
            ID.unique(),                         // Bucket ID (auto-generated)
            'My Image Bucket',                   // Bucket name
            [
                Permission.read(Role.any()),     // Anyone can read files
                Permission.write(Role.any())     // Anyone can upload files
            ],
            false,                               // File security (disabled for simplicity)
            true,                                // Enable bucket
            undefined,                           // Maximum file size (optional)
            undefined,                           // Allowed file extensions (optional)
            undefined,                           // Compression (optional)
            undefined,                           // Encryption (optional)
            undefined                            // Antivirus (optional)
        );

        const bucketId = bucket.$id;
        console.log(`Bucket created: ${bucketId}`);

        // 2. Upload the file with public read permission
        const uploadedFile = await storage.createFile(
            bucketId,
            ID.unique(),                         // File ID (auto-generated)
            file,
            [Permission.read(Role.any())]        // File-level permission: public read
        );

        const fileId = uploadedFile.$id;
        console.log(`File uploaded: ${fileId}`);

        // 3. Get the preview URL (supports image transformations)
        const previewUrl = storage.getFilePreview(
            bucketId,
            fileId,
            400,                                 // Width (optional)
            400,                                 // Height (optional)
            'center',                            // Gravity (optional)
            100,                                 // Quality (optional)
            0,                                   // Border width (optional)
            '',                                  // Border color (optional)
            0,                                   // Border radius (optional)
            0,                                   // Opacity (optional)
            -360,                                // Rotation (optional)
            '',                                  // Background color (optional)
            'output.webp'                        // Output format (optional)
        );

        console.log(`Preview URL: ${previewUrl}`);
        return previewUrl;

    } catch (error) {
        console.error('Error:', error.message);
        throw error;
    }
}

// Example usage (assuming you have a file from an <input type="file">)
// const fileInput = document.querySelector('input[type="file"]');
// fileInput.addEventListener('change', async (event) => {
//     const file = event.target.files[0];
//     if (file) {
//         const url = await createBucketAndUploadImage(file);
//         // Use the URL, e.g., set an <img> src
//         document.querySelector('img').src = url;
//     }
// });
```

### Key Points

- **Permissions**:
  - Bucket-level: `Permission.read(Role.any())` and `Permission.write(Role.any())` allow anyone to read and upload files. In production, replace `Role.any()` with `Role.user('USER_ID')`, `Role.team('TEAM_ID')`, or `Role.guest()` as needed.
  - File-level: The uploaded file is given `Permission.read(Role.any())` so the preview URL is publicly accessible. You can omit this to inherit bucket permissions.

- **Preview URL**: `getFilePreview` returns a URL that can be used directly in an `<img>` tag. It supports optional transformations (width, height, quality, format, etc.). For a simple view URL without transformations, use `storage.getFileView(bucketId, fileId)`.

- **Error Handling**: The `try/catch` block catches any Appwrite API errors (e.g., invalid permissions, quota exceeded).

- **SDK Version**: This code uses the Appwrite Web SDK v1.x. Ensure you have installed it via `npm install appwrite` or included it via CDN.

For a production environment, always restrict permissions to the minimum required (e.g., only authenticated users can write, and only the file owner or specific roles can read).

Below is an example using the Appwrite Web SDK to subscribe to realtime database document changes and storage file uploads simultaneously, with separate handling for each event type.

```javascript
import { Client } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')   // Replace with your endpoint
  .setProject('<PROJECT_ID>');                   // Replace with your project ID

// Define the channels you want to subscribe to
const databaseChannel = 'databases.<DATABASE_ID>.collections.<COLLECTION_ID>.documents';
const storageChannel = 'buckets.<BUCKET_ID>.files';

const channels = [databaseChannel, storageChannel];

// Subscribe to both channels
const unsubscribe = await client.subscribe(channels, (response) => {
  const { events, data } = response;

  // Check if the event is related to the database
  if (events.some(event => event.startsWith('databases.'))) {
    // Database document change event
    const eventType = events[0]; // e.g., ...documents.create, .update, .delete
    console.log('📄 Document event:', eventType, data);

    // Handle accordingly (e.g., update UI, sync state)
    // data contains the document payload

  } else if (events.some(event => event.startsWith('buckets.'))) {
    // Storage file event (create, update, delete)
    const eventType = events[0]; // e.g., ...files.create, .update, .delete
    console.log('📁 File event:', eventType, data);

    // Handle file uploads/updates/deletions
    // data contains the file object
  }
});

// To stop listening later, call:
// unsubscribe();
```

**Explanation**  
- We use `client.subscribe(channels, callback)`, passing an array of channel strings to subscribe to both database and storage events.
- The callback receives a `response` object with an `events` array. We inspect the first event (or any event) to determine whether it originated from the database or storage.
- For database events, `data` holds the document payload. For storage events, `data` holds the file payload.
- Each event type is handled separately, allowing you to update your UI or trigger different logic (e.g., showing a notification for new files, updating a table for document changes).

Make sure the user is authenticated if the collection or bucket requires read permissions, and replace placeholders like `<DATABASE_ID>`, `<COLLECTION_ID>`, and `<BUCKET_ID>` with actual IDs.

The exact channel strings are:

- **TablesDB (Database):** `databases.{databaseId}.collections.{collectionId}.documents`
- **Storage (Bucket):** `buckets.{bucketId}.files`

You can subscribe to both simultaneously by passing an array of channel strings to a single `subscribe()` call:

```javascript
import { Client } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID');

client.subscribe([
    'databases.YOUR_DATABASE_ID.collections.YOUR_COLLECTION_ID.documents',
    'buckets.YOUR_BUCKET_ID.files'
], (response) => {
    console.log('Realtime event:', response);
});
```

Replace `YOUR_DATABASE_ID`, `YOUR_COLLECTION_ID`, and `YOUR_BUCKET_ID` with your actual resource IDs. The callback will fire for events on either channel.

To implement email/password authentication with the Appwrite Web SDK, follow these steps.

### 1. Installation
First, install the Appwrite SDK:
```bash
npm install appwrite
```

### 2. Implementation
Here is the code to initialize the client and handle signup and login.

```javascript
import { Client, Account, ID } from "appwrite";

// 1. Setup Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('<YOUR_PROJECT_ID>');           // Your Project ID

const account = new Account(client);

// 2. Signup (Create Account)
async function signup(email, password, name) {
    try {
        const response = await account.create(
            ID.unique(), 
            email, 
            password, 
            name
        );
        console.log("Account created successfully:", response);
    } catch (error) {
        console.error("Signup failed:", error.message);
    }
}

// 3. Login (Create Session)
async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(
            email, 
            password
        );
        console.log("Session created successfully:", session);
    } catch (error) {
        console.error("Login failed:", error.message);
    }
}
```

### Key Details:
*   **`ID.unique()`**: This generates a unique ID for the user document. You can also provide a custom string ID if preferred.
*   **`setEndpoint`**: If you are using Appwrite Cloud, use `https://cloud.appwrite.io/v1`. If you are self-hosting, use your server's domain or IP address.
*   **Error Handling**: Always wrap these calls in `try/catch` blocks, as Appwrite will throw an error if the email is already taken, the password is too weak, or credentials are invalid.
*   **Security**: Ensure your Project ID is stored in an environment variable (`.env`) rather than hardcoded in production applications.

Appwrite uses the **Databases** service (not "TablesDB") to manage data. In Appwrite, you create a **Database**, then a **Collection** (which acts as your table), and then you define **Attributes** (columns) before inserting **Documents** (rows).

Here is the code using the Appwrite Web SDK.

### Prerequisites
Ensure you have installed the SDK:
```bash
npm install appwrite
```

### Implementation

```javascript
import { Client, Databases, ID } from "appwrite";

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID');              // Your Project ID

const databases = new Databases(client);

const DATABASE_ID = 'my_database';
const COLLECTION_ID = 'tasks';

async function setupAndInsert() {
    try {
        // 1. Create the Database
        await databases.create(DATABASE_ID, "My Tasks DB");
        console.log("Database created");

        // 2. Create the Collection
        await databases.createCollection(DATABASE_ID, COLLECTION_ID, "Tasks Collection");
        console.log("Collection created");

        // 3. Create Attributes (Columns)
        // Note: Attribute creation is asynchronous. 
        await databases.createStringAttribute(DATABASE_ID, COLLECTION_ID, 'title', 255, true);
        await databases.createBooleanAttribute(DATABASE_ID, COLLECTION_ID, 'completed', true);
        await databases.createDatetimeAttribute(DATABASE_ID, COLLECTION_ID, 'dueDate', true);
        console.log("Attributes created");

        // IMPORTANT: Wait a few seconds here for the attributes to be ready 
        // on the server before attempting to insert a document.
        await new Promise(resolve => setTimeout(resolve, 3000));

        // 4. Insert a Row (Document)
        const response = await databases.createDocument(
            DATABASE_ID,
            COLLECTION_ID,
            ID.unique(),
            {
                title: "Finish Appwrite project",
                completed: false,
                dueDate: new Date().toISOString()
            }
        );

        console.log("Document inserted:", response);
    } catch (error) {
        console.error("Error:", error);
    }
}

setupAndInsert();
```

### Key Concepts to Remember:
1.  **Asynchronous Attributes:** When you create an attribute (like `title` or `completed`), Appwrite processes this in the background. If you try to insert a document immediately after creating the attribute, the request might fail because the attribute isn't "ready" yet. In production, you should check the attribute status or use a retry mechanism.
2.  **IDs:** I used `ID.unique()` for the document ID, which is the recommended practice.
3.  **Data Types:**
    *   `createStringAttribute`: Requires a size (e.g., 255).
    *   `createBooleanAttribute`: Does not require size.
    *   `createDatetimeAttribute`: Does not require size.
    *   The final boolean parameter in these methods (`true`) indicates that the field is **required**.

In Appwrite, data is organized into **Databases** and **Collections** (rather than "TablesDB"). To retrieve documents from a collection, you use the `databases.listDocuments()` method, passing an array of `Query` objects to filter, sort, and paginate your results.

**Important Note:** For any attribute you wish to query (filter or sort), you **must** create an Index for that attribute in the Appwrite Console.

Here is how to use the `Query` class effectively.

---

### 1. Filtering
Filtering allows you to narrow down results based on attribute values.

*   **`Query.equal(attribute, value)`**: Matches documents where the attribute equals the value.
*   **`Query.notEqual(attribute, value)`**: Matches documents where the attribute does not equal the value.
*   **`Query.greaterThan(attribute, value)`**: Matches documents where the attribute is greater than the value.
*   **`Query.contains(attribute, value)`**: Checks if an array or string contains the specified value.

```javascript
import { Query } from 'appwrite';

const response = await databases.listDocuments(
    'databaseId',
    'collectionId',
    [
        Query.equal('status', 'active'),
        Query.greaterThan('age', 18)
    ]
);
```

---

### 2. Sorting
You can sort results by any indexed attribute in ascending or descending order.

*   **`Query.orderAsc(attribute)`**
*   **`Query.orderDesc(attribute)`**

```javascript
const response = await databases.listDocuments(
    'databaseId',
    'collectionId',
    [
        Query.orderDesc('createdAt')
    ]
);
```

---

### 3. Limiting
Use `Query.limit()` to restrict the number of documents returned in a single request. The default limit is 25, and the maximum is 100.

```javascript
const response = await databases.listDocuments(
    'databaseId',
    'collectionId',
    [
        Query.limit(10)
    ]
);
```

---

### 4. Pagination
There are two ways to handle pagination in Appwrite:

#### A. Offset-based (Simple)
Use `Query.offset()` to skip a specific number of documents. This is useful for "Page 1, Page 2" style navigation.

```javascript
// Get the second page (assuming limit is 10)
const response = await databases.listDocuments(
    'databaseId',
    'collectionId',
    [
        Query.limit(10),
        Query.offset(10) 
    ]
);
```

#### B. Cursor-based (Recommended for Performance)
Cursor-based pagination is more efficient for large datasets and infinite scrolling. You pass the ID of the last document retrieved to `Query.cursorAfter()`.

```javascript
// Fetch the first batch
const firstBatch = await databases.listDocuments('dbId', 'colId', [Query.limit(10)]);
const lastId = firstBatch.documents[firstBatch.documents.length - 1].$id;

// Fetch the next batch
const nextBatch = await databases.listDocuments('dbId', 'colId', [
    Query.limit(10),
    Query.cursorAfter(lastId)
]);
```

---

### Putting it all together
You can combine these queries into a single array. Appwrite will process them to return the exact subset of data you need.

```javascript
const documents = await databases.listDocuments(
    'databaseId',
    'collectionId',
    [
        Query.equal('category', 'news'),      // Filter
        Query.orderDesc('publishedAt'),      // Sort
        Query.limit(20),                     // Limit
        Query.offset(0)                      // Pagination
    ]
);
```

**Pro-Tip:** Always check the [Appwrite Documentation on Queries](https://appwrite.io/docs/products/databases/queries) for the most up-to-date list of available query methods, as new operators are added frequently.

To filter, sort, and limit your results in Appwrite, you pass an array of `Query` methods to the `listDocuments` function.

Here is the implementation:

```javascript
import { Client, Databases, Query } from 'appwrite';

const databases = new Databases(client);

const response = await databases.listDocuments(
    '[DATABASE_ID]',
    '[COLLECTION_ID]',
    [
        Query.greaterThan('your_numeric_field', 100),
        Query.orderDesc('your_numeric_field'),
        Query.limit(20)
    ]
);
```

### Explanation of the Queries:
*   **`Query.greaterThan('field', 100)`**: Filters the documents to include only those where the specified numeric field is strictly greater than 100.
*   **`Query.orderDesc('field')`**: Sorts the resulting documents by the specified field in descending order (highest to lowest).
*   **`Query.limit(20)`**: Restricts the response to a maximum of 20 documents.

**Note:** Ensure that the field you are querying and sorting by has an **Index** created in your Appwrite Console for that collection to ensure optimal performance.

To create an Appwrite Function in Node.js that processes a JSON body, you use the `context` object provided by the runtime.

Here is the code for your `index.js` file:

```javascript
module.exports = async function (context) {
  const { req, res } = context;

  // Appwrite automatically parses JSON bodies if the Content-Type is application/json
  const name = req.body.name || 'Guest';

  // Return a JSON response
  return res.json({
    message: `Hello, ${name}!`,
  });
};
```

### Key Details:
*   **`context`**: This object contains the `req` (request) and `res` (response) objects.
*   **`req.body`**: When the request `Content-Type` is `application/json`, Appwrite automatically parses the body into a JavaScript object.
*   **`res.json()`**: This is the standard helper method to return a JSON response with the correct `application/json` header.
*   **Entry Point**: Ensure your `package.json` file points to this file (e.g., `"main": "index.js"`).

To perform these operations using the Appwrite Web SDK, you will need to initialize the `Client` and `Storage` services.

**Note:** Creating buckets from the client-side SDK is possible, but ensure your project security settings allow the current user to perform the `buckets.create` scope.

### Implementation

```javascript
import { Client, Storage, ID, Permission, Role } from "appwrite";

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID'); // Your Project ID

const storage = new Storage(client);

async function setupStorage(fileObject) {
    try {
        // 1. Create a Bucket
        // We set read access to everyone and write access to authenticated users
        const bucket = await storage.createBucket(
            ID.unique(), 
            "User Uploads", 
            [
                Permission.read(Role.any()),
                Permission.write(Role.users())
            ]
        );
        console.log("Bucket created:", bucket.$id);

        // 2. Upload a File
        // fileObject should be a File object from an <input type="file">
        const uploadedFile = await storage.createFile(
            bucket.$id,
            ID.unique(),
            fileObject
        );
        console.log("File uploaded:", uploadedFile.$id);

        // 3. Get Preview URL
        // Generates a 200x200px preview
        const previewUrl = storage.getFilePreview(
            bucket.$id, 
            uploadedFile.$id, 
            200, 
            200
        );

        console.log("Preview URL:", previewUrl);
        return previewUrl;

    } catch (error) {
        console.error("Error:", error.message);
    }
}
```

### Key Concepts

1.  **Permissions:** We use `Permission.read(Role.any())` to make the files public (accessible via URL) and `Permission.write(Role.users())` to restrict uploads to logged-in users.
2.  **`ID.unique()`:** This helper generates a unique ID for both the bucket and the file. You can also provide your own string IDs if preferred.
3.  **`getFilePreview`:** This method returns a URL string. It does not perform an API request; it constructs the URL based on your project configuration, allowing you to use it directly in an `<img>` tag's `src` attribute.
4.  **File Object:** The `createFile` method expects a standard browser `File` object (e.g., `document.getElementById('file-input').files[0]`).

To set up push notifications in Appwrite, you must configure a messaging provider, register your client devices, and then use the Messaging API to send notifications.

### Supported Providers
Appwrite Messaging currently supports the following providers:
*   **FCM (Firebase Cloud Messaging):** Used for Android and Web push notifications.
*   **APNs (Apple Push Notification service):** Used for iOS push notifications.

---

### Setup Workflow

#### 1. Configure the Provider in Appwrite Console
1.  Navigate to your **Appwrite Console**.
2.  Go to **Messaging** > **Providers**.
3.  Click **Add Provider** and select **FCM** or **APNs**.
4.  Provide the required credentials (e.g., the Service Account JSON file for FCM or the `.p8` key file for APNs).

#### 2. Register the Device (Client-Side)
Before you can send a notification, the client application must register the device token with Appwrite.
*   **Get the Token:** Use the native OS SDK (Firebase SDK for Android/Web or Apple's `UserNotifications` framework for iOS) to retrieve the device token.
*   **Register with Appwrite:** Use the Appwrite Client SDK to register this token as a "Subscriber."

```javascript
// Example using Appwrite Web SDK
import { Client, Messaging, ID } from "appwrite";

const client = new Client().setProject('YOUR_PROJECT_ID');
const messaging = new Messaging(client);

// Register the device token
await messaging.createSubscriber(
    ID.unique(), // Subscriber ID
    'topic-name', // Topic to subscribe to
    'device-token-from-os' // The token retrieved from FCM/APNs
);
```

---

### Sending a Push Notification to a Topic
Topics allow you to broadcast messages to a group of subscribers. You do not need to create the topic explicitly in the console; simply referencing a topic name when creating a message will target all subscribers associated with that topic.

Use the **Appwrite Server SDK** to send the message:

```javascript
const { Client, Messaging, ID } = require('node-appwrite');

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID')
    .setKey('YOUR_API_KEY');

const messaging = new Messaging(client);

const promise = messaging.createMessage(
    ID.unique(), // Message ID
    ['news-updates'], // Array of topic names
    'Breaking News', // Title
    'Appwrite just released a new feature!', // Body
    {
        data: { 'key': 'value' } // Optional custom data
    }
);

promise.then(function (response) {
    console.log(response);
}, function (error) {
    console.log(error);
});
```

### Key Considerations
*   **Permissions:** Ensure your API Key has the `messaging.write` scope enabled.
*   **Targeting:** You can send messages to specific `topics`, specific `users`, or specific `targets` (individual device tokens).
*   **Environment:** Always use the Server SDK for sending messages to keep your API keys secure.

To send push notifications to a topic in Appwrite, you must use the **Messaging** service.

### Prerequisites (What must be configured first)

Before you can send a notification, the following must be completed:

1.  **Configure Providers:** In the Appwrite Console, navigate to **Messaging > Providers** and configure your push notification providers (FCM for Android/Web or APNs for iOS).
2.  **Register Device Tokens:** Your client application must register the device token with Appwrite using the Client SDK (e.g., `account.createPushTarget`).
3.  **Subscribe to Topics:** The client application must subscribe the registered device/user to the specific topic using the Client SDK:
    ```javascript
    // Client-side example
    await messaging.subscribe('topic-name', ['target-id']);
    ```

---

### Steps to Send the Notification

Once the prerequisites are met, you send the notification using the **Appwrite Server SDK** (or REST API). You do not send these from the client for security reasons.

1.  **Initialize the Messaging Service:** Use your project's API key.
2.  **Call `createPush`:** Use the `messaging.createPush` method.
3.  **Target the Topic:** Pass the topic name inside the `topics` array parameter.

#### Example (Node.js Server SDK)

```javascript
const sdk = require('node-appwrite');

const client = new sdk.Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID')
    .setKey('YOUR_API_KEY');

const messaging = new sdk.Messaging(client);

const promise = messaging.createPush(
    sdk.ID.unique(), // Message ID
    'Hello World',   // Title
    'This is a notification sent to a topic.', // Body
    {},              // Data (optional)
    ['topic-name'],  // Topics (Targeting the topic here)
    [],              // Users (Optional)
    []               // Targets (Optional)
);

promise.then(function (response) {
    console.log(response);
}, function (error) {
    console.log(error);
});
```

### Key Notes
*   **Topics vs. Users:** You can target specific topics, specific user IDs, or specific device targets. You can also combine these in a single `createPush` call.
*   **Asynchronous:** The `createPush` method queues the message; Appwrite handles the delivery to the configured providers (FCM/APNs) asynchronously.

To subscribe to both database document changes and file uploads simultaneously, you pass an array of channel strings to the `client.subscribe()` method. You can then distinguish between the events by inspecting the `events` array within the response payload.

Here is the implementation:

```javascript
import { Client } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID');

const DATABASE_ID = 'YOUR_DATABASE_ID';
const COLLECTION_ID = 'YOUR_COLLECTION_ID';
const BUCKET_ID = 'YOUR_BUCKET_ID';

// Subscribe to both channels
const unsubscribe = client.subscribe([
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
    `buckets.${BUCKET_ID}.files`
], (response) => {
    const event = response.events[0];

    // Handle events differently based on the event string
    if (event.includes('databases')) {
        console.log('Database change detected:', response.payload);
        handleDatabaseChange(response);
    } else if (event.includes('buckets')) {
        console.log('File upload/change detected:', response.payload);
        handleFileChange(response);
    }
});

function handleDatabaseChange(response) {
    // Logic for document create, update, or delete
    console.log('Processing DB event:', response.events[0]);
}

function handleFileChange(response) {
    // Logic for file create, update, or delete
    console.log('Processing File event:', response.events[0]);
}

// Call unsubscribe() when the component unmounts or the listener is no longer needed
// unsubscribe();
```

### Key Details:
1.  **Channel Syntax**: 
    *   Database: `databases.[DATABASE_ID].collections.[COLLECTION_ID].documents`
    *   Storage: `buckets.[BUCKET_ID].files`
2.  **Event Identification**: The `response.events` property is an array containing the specific event string (e.g., `databases.*.collections.*.documents.*.create`). Using `.includes()` or a `switch` statement on `response.events[0]` is the most reliable way to route the logic.
3.  **Cleanup**: Always store the return value of `client.subscribe()` and call it (e.g., `unsubscribe()`) when your component unmounts to prevent memory leaks.

