  const tableId = "tasks";
  const permissions = ["role:all"]; // ⚠️ Use specific roles/users in production

  try {
    // 2. Create Database
    await tables.createDatabase(databaseId, "Tasks Database", true);
    console.log("✅ Database created");

    // 3. Create Table
    await tables.create(databaseId, tableId, "Tasks", permissions);
    console.log("✅ Table created");

    // 4. Create Columns
    // title (varchar/string)
    await tables.createColumn(
      databaseId, tableId, "title", "string", 
      true, false, null, null, null, [], null, null, true, 255
    );

    // completed (boolean)
    await tables.createColumn(
      databaseId, tableId, "completed", "boolean", 
      false, false, false
    );

    // dueDate (datetime)
    await tables.createColumn(
      databaseId, tableId, "dueDate", "datetime", 
      false, false, null, null, null, [], null, null, true, null
    );

    console.log("✅ Columns created");

    // 5. Insert a Row
    const newRow = await tables.createRow(databaseId, tableId, {
      title: "Complete Appwrite integration",
      completed: false,
      dueDate: new Date().toISOString() // Appwrite expects ISO 8601 format
    }, permissions);

    console.log("✅ Row inserted:", newRow);
  } catch (error) {
    console.error("❌ Setup failed:", error.message);
  }
}

setupTasksTable();
```

### 🔑 Key Notes:
1. **SDK Version**: Requires `appwrite` Web SDK `v16.0.0` or newer (`npm install appwrite@latest`).
2. **Column Parameters**: `createColumn` uses positional arguments. Unused parameters are passed as `null` or `false` to maintain correct ordering.
3. **Permissions**: `["role:all"]` grants public read/write access. For production, replace with specific roles like `["user:<userId>"]` or `["team:<teamId>"]`.
4. **Datetime Format**: Appwrite's `datetime` type strictly expects **ISO 8601** strings (e.g., `"2024-12-31T23:59:59.000Z"`).
5. **Idempotency**: Running this script twice will throw `409 Conflict` errors. Add existence checks or use `try/catch` with `error.code === 409` for idempotent setups in real apps.

Here's the correct Appwrite Function implementation in Node.js:

```javascript
module.exports = async function(req, res) {
  // Appwrite automatically parses JSON bodies when Content-Type is application/json
  const { name } = req.body || {};

  if (!name) {
    return res.status(400).json({ error: 'Missing "name" field in request body' });
  }

  return res.status(200).json({ greeting: `Hello, ${name}!` });
};
```

### Key Appwrite Function Details:
- **Signature**: `module.exports = async function(req, res) { ... }` is the required entry point for Node.js runtimes in Appwrite.
- **Request (`req`)**: `req.body` is pre-parsed when the client sends `Content-Type: application/json`.
- **Response (`res`)**: Use `res.status(code).json(data)` or `res.send()` to return responses. Appwrite automatically handles headers and serialization.
- **Error Handling**: Returning a `400` status for missing fields follows REST best practices and integrates cleanly with Appwrite's function execution logs.

