async function manageImageStorage() {
  try {
    // 2. Create a storage bucket with permissions
    const bucket = await storage.createBucket(
      ID.unique(),                     // Auto-generate bucket ID
      'user-images',                   // Bucket name
      [Permission.read(Role.any())],   // Bucket-level permissions
      true,                            // Enabled
      undefined,                       // Max file size (default: 10MB)
      ['jpg', 'png', 'gif', 'webp'],   // Allowed extensions
      true,                            // Encryption enabled
      true                             // Antivirus scanning enabled
    );
    console.log('✅ Bucket created:', bucket.$id);

    // 3. Upload a file (replace with your actual File object)
    // Example: const fileToUpload = document.getElementById('fileInput').files[0];
    const fileToUpload = new File([''], 'sample.jpg', { type: 'image/jpeg' }); // Placeholder

    const uploadedFile = await storage.createFile(
      bucket.$id,
      ID.unique(),                     // Auto-generate file ID
      fileToUpload,
      [Permission.read(Role.any())]    // File-level permissions (overrides bucket if set)
    );
    console.log('✅ File uploaded:', uploadedFile.$id);

    // 4. Generate a preview URL for the image
    const previewUrl = storage.getFilePreview(
      bucket.$id,
      uploadedFile.$id,
      400,   // width (px)
      300,   // height (px)
      'center', // gravity
      90,    // quality (0-100)
      0,     // borderWidth
      '',    // borderColor
      0,     // borderRadius
      100,   // opacity
      0,     // rotation
      'webp' // output format
    );
    console.log('🖼️ Preview URL:', previewUrl);

    return { bucketId: bucket.$id, fileId: uploadedFile.$id, previewUrl };
  } catch (error) {
    console.error('❌ Appwrite Storage Error:', error);
  }
}

// Execute
manageImageStorage();
```

### 🔑 Key Notes:
1. **Permissions**: 
   - `Permission.read(Role.any())` grants public read access. For authenticated-only access, use `Permission.read(Role.users())` or `Permission.read(Role.user('USER_ID'))`.
   - Bucket permissions apply to all files by default. File-level permissions override bucket permissions if specified.
2. **Preview URL**: `getFilePreview()` returns a **string URL**, not a Promise. If the file is private, the SDK automatically appends a temporary JWT to the URL for secure access.
3. **File Input**: In a real app, get the `File` object from an HTML `<input type="file">` or drag-and-drop handler.
4. **Security**: Avoid `Role.any()` in production unless the bucket is explicitly public. Use `Role.users()` or team/user-specific roles for controlled access.

