# Appwrite Email/Password Authentication Implementation

Here's a complete implementation using the Appwrite Web SDK:

## 1. Initialize the Appwrite Client

```javascript
import { Client, Account, ID } from "appwrite";

// Initialize the client
const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1") // Your Appwrite endpoint
  .setProject("YOUR_PROJECT_ID");              // Your project ID

// Initialize the Account service
const account = new Account(client);

export { client, account, ID };
```

## 2. Sign Up (Create Account)

```javascript
import { client, account, ID } from "./appwrite";

async function signup(email, password, name) {
  try {
    // Create a new user account
    const user = await account.create(
      ID.unique(),      // Generate unique ID
      email,
      password,
      name              // User's display name
    );

    console.log("Account created successfully:", user);
    return user;
  } catch (error) {
    console.error("Signup failed:", error.message);
    throw error;
  }
}
```

## 3. Login (Create Session)

```javascript
import { client, account } from "./appwrite";

async function login(email, password) {
  try {
    // Create a session for the user
    const session = await account.createEmailPasswordSession(
      email,
      password
    );

    console.log("Session created:", session);

    // Store session token for persistence
    client.setSession(session.$id);

    return session;
  } catch (error) {
    console.error("Login failed:", error.message);
    throw error;
  }
}
```

## 4. Logout (Delete Session)

```javascript
import { account } from "./appwrite";

async function logout() {
  try {
    await account.deleteSession("current");

    console.log("Logged out successfully");
  } catch (error) {
    console.error("Logout failed:", error.message);
    throw error;
  }
}
```

