# Appwrite TablesDB Web SDK Usage

Here's the code to create a database, table with columns, and insert a row using the Appwrite Web SDK with the TablesDB API:

```javascript
import { Client, Databases, ID } from "appwrite";

// Initialize the client
const client = new Client()
    .setEndpoint("https://cloud.appwrite.io/v1") // or your self-hosted endpoint
    .setProject("YOUR_PROJECT_ID"); // your project ID

const databases = new Databases(client);

// Configuration constants
const DATABASE_ID = "my-database-id";
const TABLE_ID = "tasks";

// Define the table columns
const columns = [
    { key: "title", type: "varchar", size: 255, required: true },
    { key: "completed", type: "boolean", required: false },
    { key: "dueDate", type: "datetime", required: false }
];

async function setupDatabase() {
    try {
        // 1. Create the database
        const database = await databases.create(
            DATABASE_ID,
            "Task Database"
        );
        console.log("Database created:", database);

        // 2. Create the table with columns
        const table = await databases.createTable(
            DATABASE_ID,
            TABLE_ID,
            "Tasks",           // display name
            columns            // column definitions
        );
        console.log("Table created:", table);

        // 3. Insert a row (document) into the table
        const document = await databases.createDocument(
            DATABASE_ID,
            TABLE_ID,
            ID.unique(),      // generate unique document ID
            {
                title: "Complete Appwrite setup",
                completed: false,
                dueDate: new Date("2025-02-15T10:00:00Z").toISOString()
            }
        );
        console.log("Document inserted:", document);

        return { database, table, document };

    } catch (error) {
        console.error("Error:", error);
        throw error;
    }
}

// Run the setup
setupDatabase();
```

## Key Points

| Component | Method | Description |
|-----------|--------|-------------|
| Database | `databases.create()` | Creates a new database |
| Table | `databases.createTable()` | Creates a table with column schema |
| Document | `databases.createDocument()` | Inserts a row into the table |

