# Appwrite Web SDK - Bucket Creation, File Upload & Preview URL

Here's a comprehensive example covering all three operations with proper permission configuration.

## Prerequisites

```bash
npm install appwrite
```

## Complete Implementation

```javascript
import { Client, Storage, Permission, Role } from "appwrite";

// ============================================
// 1. Initialize Appwrite Client
// ============================================
const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1") // Your Appwrite endpoint
  .setProject("YOUR_PROJECT_ID");              // Your Project ID

// ============================================
// 2. Initialize Storage Service
// ============================================
const storage = new Storage(client);

// ============================================
// 3. Configuration Constants
// ============================================
const BUCKET_ID = "profile-pictures";
const FILE_ID = "unique-file-id"; // Optional, auto-generated if omitted
const FILE_PATH = "/path/to/image.jpg"; // Path to your image file

// ============================================
// 4. Create Bucket with Permissions
// ============================================
async function createBucket() {
  try {
    const bucket = await storage.createBucket(
      BUCKET_ID,                          // Bucket ID (unique)
      "Profile Pictures",                 // Name
      ["image/jpeg", "image/png", "image/webp"], // Allowed file extensions
      ["jpg", "jpeg", "png", "webp"],      // Allowed MIME types
      10 * 1024 * 1024,                   // Maximum file size (10MB)
      false,                               // File encryption enabled?
      false,                               // Bucket encryption enabled?
      ["pictures", "profile"],             // (v1.4+) Tags
      true,                               // (v1.4+) Enabled?
      [
        // ---- Permissions Configuration ----
        Permission.read(Role.users()),                    // Users can read
        Permission.read(Role.guests()),                   // Guests can read
        Permission.create(Role.users()),                   // Users can create/upload
        Permission.update(Role.any()),                    // Anyone can update (use carefully!)
        Permission.delete(Role.team("admin")),            // Only admin team can delete
      ]
    );

    console.log("✅ Bucket created:", bucket.$id);
    return bucket;
  } catch (error) {
    if (error.code === 409) {
      console.log("ℹ️ Bucket already exists, continuing...");
    } else {
      console.error("❌ Error creating bucket:", error);
      throw error;
    }
  }
}

// ============================================
// 5. Upload File with Permissions
// ============================================
async function uploadFile() {
  try {
    // Create a file input in your HTML:
    // <input type="file" id="fileInput" accept="image/*" />

    const fileInput = document.getElementById("fileInput");
    const selectedFile = fileInput.files[0];

    if (!selectedFile) {
      throw new Error("No file selected");
    }

    const file = await storage.createFile(
      BUCKET_ID,
      FILE_ID,
      selectedFile,
      [
        // ---- File-Level Permissions ----
        Permission.read(Role.users()),                   // All users can read
        Permission.read(Role.user("user-id-here")),       // Specific user can read
        Permission.update(Role.users()),                 // Users can update
        Permission.delete(Role.user("user-id-here")),    // Only uploader can delete
      ]
    );

    console.log("✅ File uploaded:", file.$id);
    return file;
  } catch (error) {
    console.error("❌ Error uploading file:", error);
    throw error;
  }
}

// ============================================
// 6. Get Preview URL for Image
// ============================================
function getPreviewUrl(fileId, options = {}) {
  const defaultOptions = {
    width: 800,              // Image width
    height: 600,             // Image height
    quality: 80,             // Image quality (1-100)
    background: "#FFFFFF",   // Background color
    output: "image/jpeg",    // Output format
    borderWidth: 0,          // Border width
    borderColor: "#000000",   // Border color
    borderRadius: 0,         // Border radius
    gravity: "center",       // Image gravity
  };

  const finalOptions = { ...defaultOptions, ...options };

  try {
    const previewUrl = storage.getPreview(
      fileId,
      BUCKET_ID,
      finalOptions.width,
      finalOptions.height,
      finalOptions.quality,
      finalOptions.background,
      finalOptions.output,
      finalOptions.borderWidth,
      finalOptions.borderColor,
      finalOptions.borderRadius,
      finalOptions.gravity
    );

    console.log("✅ Preview URL generated:", previewUrl);
    return previewUrl;
  } catch (error) {
    console.error("❌ Error generating preview:", error);
    throw error;
  }
}

// ============================================
// 7. Main Execution Flow
// ============================================
async function main() {
  try {
    // Step 1: Create bucket
    await createBucket();

    // Step 2: Upload file (after user selects a file)
    // const uploadedFile = await uploadFile();

    // Step 3: Get preview URL
    const previewUrl = getPreviewUrl("your-file-id", {
      width: 400,
      height: 400,
      quality: 75,
      output: "image/webp",
    });

    console.log("Image preview URL:", previewUrl);

    // Use in your HTML
    // document.getElementById("preview").src = previewUrl;

    return previewUrl;
  } catch (error) {
    console.error("❌ Main execution failed:", error);
  }
}

// Run the example
main();
```

## Permission Roles Reference

| Role | Description |
|------|-------------|
| `Role.users()` | Any authenticated user |
| `Role.user("id")` | Specific user by ID |
| `Role.guests()` | Unauthenticated users |
| `Role.team("teamId")` | All members of a team |
| `Role.member("memberId")` | Specific team member |
| `Role.any()` | Anyone (authenticated or not) |

