Here's how to use the Appwrite Web SDK (v4.0+) to create a database, table (collection), and insert a row using the new Tables API (currently in beta as of Appwrite 1.5):

```javascript
import { Client, Databases, ID } from "appwrite";

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your API endpoint
  .setProject('YOUR_PROJECT_ID');              // Your project ID

const databases = new Databases(client);

// 1. Create a database
const createDatabase = async () => {
  try {
    const database = await databases.create(ID.unique(), 'TaskManager');
    console.log('Database created:', database);
    return database.$id;
  } catch (error) {
    console.error('Error creating database:', error);
  }
};

// 2. Create a collection (table) with attributes
const createCollection = async (databaseId) => {
  try {
    // Create collection
    const collection = await databases.createCollection(
      databaseId,
      ID.unique(),
      'tasks'
    );

    // Create attributes
    await databases.createStringAttribute(
      databaseId,
      collection.$id,
      'title',
      255,
      true
    );

    await databases.createBooleanAttribute(
      databaseId,
      collection.$id,
      'completed',
      true
    );

    await databases.createDatetimeAttribute(
      databaseId,
      collection.$id,
      'dueDate',
      false
    );

    console.log('Collection created with attributes');
    return collection.$id;
  } catch (error) {
    console.error('Error creating collection:', error);
  }
};

// 3. Insert a row (document)
const createTask = async (databaseId, collectionId) => {
  try {
    const task = await databases.createDocument(
      databaseId,
      collectionId,
      ID.unique(),
      {
        title: 'Complete Appwrite project',
        completed: false,
        dueDate: new Date('2023-12-31T23:59:59.999Z').toISOString()
      }
    );
    console.log('Task created:', task);
  } catch (error) {
    console.error('Error creating task:', error);
  }
};

// Execute the operations
(async () => {
  const databaseId = await createDatabase();
  if (databaseId) {
    const collectionId = await createCollection(databaseId);
    if (collectionId) {
      await createTask(databaseId, collectionId);
    }
  }
})();
```

Important notes:
1. The Tables API is currently in beta (Appwrite 1.5+)
2. You'll need to enable beta features in your Appwrite project
3. Make sure to replace `YOUR_PROJECT_ID` with your actual project ID
4. The `createDatetimeAttribute` expects ISO 8601 formatted strings
5. Required attributes are marked with `true` in their creation

For production use, you should add proper error handling and potentially wait for attribute creation to complete before inserting documents.

