Here's a concise example using the Appwrite Web SDK (v10+) to create a bucket, upload a file, and get a preview URL with proper permissions:

```javascript
import { Client, Storage, ID } from "appwrite";

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your API endpoint
  .setProject('YOUR_PROJECT_ID');              // Your project ID

const storage = new Storage(client);

// 1. Create a bucket with permissions
async function createBucket() {
  try {
    const bucket = await storage.createBucket(
      ID.unique(),          // Bucket ID
      'image-bucket',       // Bucket name
      [
        Permission.read(Role.any()),    // Allow public read
        Permission.create(Role.users()), // Allow authenticated users to upload
        Permission.update(Role.users()),
        Permission.delete(Role.users())
      ],
      false,                // Not encrypted
      true                  // Enable file previews
    );
    console.log('Bucket created:', bucket);
    return bucket.$id;
  } catch (error) {
    console.error('Error creating bucket:', error);
  }
}

// 2. Upload a file
async function uploadFile(bucketId, file) {
  try {
    const response = await storage.createFile(
      bucketId,
      ID.unique(),          // File ID
      file,                 // File object from input
      [
        Permission.read(Role.any()),    // Public read
        Permission.update(Role.users()), // Authenticated update
        Permission.delete(Role.users())
      ]
    );
    console.log('File uploaded:', response);
    return response.$id;
  } catch (error) {
    console.error('Error uploading file:', error);
  }
}

// 3. Get preview URL
async function getPreviewUrl(bucketId, fileId) {
  try {
    const url = storage.getFilePreview(
      bucketId,
      fileId,
      300,    // Width (optional)
      300,    // Height (optional)
      'center', // Gravity (optional)
      80,     // Quality (optional)
      0,      // Border width (optional)
      '#000000', // Border color (optional)
      0,      // Border radius (optional)
      1,      // Opacity (optional)
      0,      // Rotation (optional)
      'FFFFFF', // Background (optional)
      'webp'  // Output format (optional)
    );
    console.log('Preview URL:', url.href);
    return url.href;
  } catch (error) {
    console.error('Error getting preview:', error);
  }
}

// Usage example
async function main() {
  const bucketId = await createBucket();
  const fileInput = document.getElementById('file-input'); // Your file input element
  fileInput.addEventListener('change', async (e) => {
    const file = e.target.files[0];
    const fileId = await uploadFile(bucketId, file);
    const previewUrl = await getPreviewUrl(bucketId, fileId);
    // Use previewUrl in your app (e.g., set as img src)
  });
}

main();
```

Key points:
1. Permissions are set at both bucket and file levels
2. `Role.any()` allows public access (use carefully)
3. `Role.users()` restricts to authenticated users
4. Preview parameters are optional - adjust as needed
5. Remember to replace `YOUR_PROJECT_ID` with your actual project ID

