### The Implementation

```javascript
import { Client, Account, ID } from "appwrite";

// 1. Setup the Client
const client = new Client();

client
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite Endpoint
    .setProject('YOUR_PROJECT_ID');               // Your Appwrite Project ID

// Initialize the Account service
const account = new Account(client);

// 2. Sign Up (Create an Account)
export async function signUp(email, password, name) {
    try {
        const userAccount = await account.create(
            ID.unique(), // Generates a unique string for the user ID
            email,
            password,
            name
        );
        console.log('Account created successfully:', userAccount);

        // Optional: Automatically log the user in after signup
        // await login(email, password);

        return userAccount;
    } catch (error) {
        console.error('Signup failed:', error.message);
        throw error;
    }
}

// 3. Log In (Create a Session)
export async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(
            email,
            password
        );
        console.log('Session created successfully:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error.message);
        throw error;
    }
}

// 4. Get Current User (Helper to check if logged in)
export async function getCurrentUser() {
    try {
        return await account.get();
    } catch (error) {
        return null; // User is not logged in or session is invalid
    }
}

// 5. Log Out (Delete Session)
export async function logout() {
    try {
        await account.deleteSession('current'); // Deletes the current active session
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout failed:', error.message);
    }
}
```

### Key Points:
* **`ID.unique()`**: Appwrite requires a unique string ID for every document and account. Using `ID.unique()` tells the Appwrite SDK to auto-generate a secure, unique ID for the new user.
* **`createEmailPasswordSession`**: This replaces the deprecated `createEmailSession` method in Appwrite SDK versions 11.x+. It authenticates the user and creates an active session, storing the session cookie in the browser.
* **Authentication Flow**: Creating an account (`account.create`) does *not* automatically log the user in. You must call `account.createEmailPasswordSession` afterward to authenticate them, or call the `login` function immediately after a successful signup.

Here is the code using the current Appwrite Web SDK (v14+) and the `TablesDB` API to accomplish your goal. 

Note that Appwrite processes column creation asynchronously on the server. Because of this, you typically need to wait a few seconds after creating columns before you can insert a row, otherwise, you might get a "Table not found" or similar error. I've included a short delay to handle this.

```javascript
import { Client, TablesDB, ID } from "appwrite";

// 1. Initialize the Client and TablesDB service
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite Endpoint
    .setProject('YOUR_PROJECT_ID');              // Your Appwrite Project ID

const tablesDB = new TablesDB(client);

async function setupTasksDatabase() {
    try {
        // 2. Create the Database
        const database = await tablesDB.createDatabase(
            ID.unique(), 
            'Tasks Database'
        );
        const databaseId = database.$id;
        console.log(`Database created: ${databaseId}`);

        // 3. Create the Table
        const table = await tablesDB.createTable(
            databaseId, 
            ID.unique(), 
            'tasks'
        );
        const tableId = table.$id;
        console.log(`Table created: ${tableId}`);

        // 4. Create Columns
        // title: Appwrite uses createStringColumn. A size <= 255 maps to a VARCHAR in the underlying database.
        await tablesDB.createStringColumn(databaseId, tableId, 'title', 255, true);

        // completed: Boolean column, required = true, default = false
        await tablesDB.createBooleanColumn(databaseId, tableId, 'completed', true, false);

        // dueDate: Datetime column, required = true
        await tablesDB.createDatetimeColumn(databaseId, tableId, 'dueDate', true);

        console.log('Columns created. Waiting for table to finish updating...');

        // Wait for the server to finish applying the schema changes.
        // In a production app, you would poll `tablesDB.getTable` until `table.status === 'available'`.
        await new Promise(resolve => setTimeout(resolve, 5000)); 

        // 5. Insert a Row
        const row = await tablesDB.createRow(
            databaseId,
            tableId,
            ID.unique(),
            {
                title: 'Buy groceries',
                completed: false,
                dueDate: '2024-12-31T23:59:59.000Z' // Must be a valid ISO 8601 string
            }
        );
        console.log('Row inserted:', row);

    } catch (error) {
        console.error('Error during setup:', error);
    }
}

setupTasksDatabase();
```

### Key Details:
* **`ID.unique()`**: Automatically generates a unique alphanumeric ID for the database, table, and row.
* **Varchar**: Appwrite does not have a distinct `createVarcharColumn` method. It uses `createStringColumn`. If you pass a `size` of 255 or less, Appwrite internally creates a `VARCHAR` in the underlying database. A size greater than 255 creates a `TEXT` column.
* **Datetime**: The `dueDate` value must be provided as a valid ISO 8601 formatted string (e.g., `YYYY-MM-DDTHH:MM:SS.sssZ`).
* **Async Schema Updates**: The `setTimeout` is a practical workaround for scripts. In a real application, you should poll the table using `tablesDB.getTable(databaseId, tableId)` until `table.status` returns `'available'` before attempting to write rows.

In Appwrite, the database service is called **Databases**, where "tables" are referred to as **Collections** and "rows" as **Documents**. 

To query documents in a collection, you pass an array of `Query` objects to the `listDocuments()` method. You can chain multiple queries together to filter, sort, limit, and paginate data.

Here is how to use the `Query` class for each operation, using the JavaScript/Web SDK as an example.

### 1. Filtering
You can filter documents using various methods like `equal`, `notEqual`, `greaterThan`, `lessThan`, `search`, etc.

```javascript
import { Client, Databases, Query } from "appwrite";

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID');

const databases = new Databases(client);

// Example: Get documents where 'status' is 'active' AND 'age' is greater than 18
const activeAdults = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.equal('status', 'active'),
        Query.greaterThan('age', 18)
    ]
);
```
*Note: You can pass an array to `Query.equal('status', ['active', 'pending'])` to filter by multiple values (acts as an OR operator).*

### 2. Sorting
To sort your results, use `Query.orderAsc()` or `Query.orderDesc()`. You can only sort by a maximum of two attributes.

```javascript
// Example: Sort by 'createdAt' descending (newest first), then by 'name' ascending
const sortedDocs = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.orderDesc('createdAt'),
        Query.orderAsc('name')
    ]
);
```

### 3. Limiting
By default, Appwrite returns a maximum of 25 documents per request (up to a hard limit of 100). Use `Query.limit()` to control the number of results returned.

```javascript
// Example: Get only the first 10 documents
const limitedDocs = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.limit(10)
    ]
);
```

### 4. Pagination
Appwrite supports two methods of pagination: **Offset-based** and **Cursor-based**. Cursor-based pagination is highly recommended for large datasets as it performs better and avoids data skipping when new documents are added.

**Offset-based Pagination:**
Use `Query.offset()` to skip a specific number of documents. Good for simple "Page 1, Page 2" UI.

```javascript
// Example: Skip the first 20 documents (useful for page 2 if limit is 20)
const offsetDocs = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.limit(20),
        Query.offset(20) 
    ]
);
```

**Cursor-based Pagination:**
Use `Query.cursorAfter()` or `Query.cursorBefore()` with the `$id` of a document. This is ideal for infinite scrolling.

```javascript
// Example: Get documents after the document with ID 'xyz789'
const nextDocs = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.limit(20),
        Query.cursorAfter('xyz789') // Fetches 20 docs after this ID
    ]
);
```

### 5. Combined Example
In a real-world scenario, you will likely combine these queries into a single request:

```javascript
const result = await databases.listDocuments(
    'YOUR_DATABASE_ID',
    'YOUR_COLLECTION_ID',
    [
        Query.equal('category', 'electronics'), // Filter
        Query.greaterThan('price', 100),         // Filter
        Query.orderDesc('price'),                // Sort
        Query.limit(25),                         // Limit
        Query.cursorAfter('lastDocIdFromPrevPage') // Paginate
    ]
);

console.log(result.documents); // The array of returned rows
console.log(result.total);     // The total number of rows matching the filters
```

Here is the Node.js code for an Appwrite Function that meets your requirements. 

In Appwrite Functions (version 1.4+), the standard signature uses an object destructuring pattern to provide `req`, `res`, `log`, and `error`. The raw request body is passed as a string in `req.body`, so it must be parsed using `JSON.parse()`.

```javascript
export default async ({ req, res, log, error }) => {
  try {
    // Parse the incoming JSON body
    const body = JSON.parse(req.body);

    // Extract the 'name' field
    const name = body.name;

    // Validate that the name field exists and is not empty
    if (!name || name.trim() === '') {
      return res.json({
        success: false,
        message: 'Please provide a "name" field in the JSON body.',
      }, 400); // 400 Bad Request
    }

    // Create the personalized greeting
    const greeting = `Hello, ${name}! Welcome to Appwrite Functions.`;

    // Log the greeting (visible in the Appwrite Console logs)
    log(greeting);

    // Return the successful response
    return res.json({
      success: true,
      greeting: greeting,
    }, 200); // 200 OK

  } catch (err) {
    // Handle cases where the body is not valid JSON
    error(`Failed to parse JSON body: ${err.message}`);

    return res.json({
      success: false,
      message: 'Invalid JSON body. Please send a valid JSON payload.',
    }, 400); // 400 Bad Request
  }
};
```

### Key Appwrite Function Details:
* **Function Signature:** `export default async ({ req, res, log, error }) => {}` is the required entry point for Node.js Appwrite Functions.
* **`req.body`:** Unlike traditional Express.js, Appwrite provides the raw payload as a string. You must explicitly use `JSON.parse(req.body)` to read incoming JSON data.
* **`res.json()`:** This method sends a JSON response. It optionally accepts a second argument for the HTTP status code (e.g., `res.json(data, 200)`).
* **`log()` and `error()`:** These built-in methods output to the Appwrite function execution logs, which are extremely useful for debugging in the Appwrite Console.

Here is the code using the Appwrite Web SDK to accomplish this. 

This example assumes you are running this in a browser environment where a user selects a file from an `<input type="file">` element.

```javascript
import { Client, Storage, ID, Permission, Role, InputFile } from "appwrite";

// 1. Initialize the Appwrite Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite Endpoint
    .setProject('YOUR_PROJECT_ID');               // Your Appwrite Project ID

const storage = new Storage(client);

async function handleImageUpload(fileInput) {
    try {
        const file = fileInput.files[0];
        if (!file) {
            console.error("No file selected.");
            return;
        }

        // 2. Create a Bucket with Permissions
        const bucketId = ID.unique();
        const bucket = await storage.createBucket(
            bucketId, 
            'My Image Bucket', 
            [
                Permission.read(Role.any()),      // Anyone can read files
                Permission.create(Role.users()),   // Only logged-in users can upload
                Permission.update(Role.users()),   // Only logged-in users can update
                Permission.delete(Role.users())    // Only logged-in users can delete
            ]
        );
        console.log("Bucket created:", bucket);

        // 3. Upload a File to the Bucket
        const fileId = ID.unique();
        const uploadedFile = await storage.createFile(
            bucketId,
            fileId,
            InputFile.fromBlob(file, file.name), // Convert browser File/Blob to InputFile
            [
                Permission.read(Role.any()),      // Make this specific file publicly readable
                Permission.update(Role.creator()),// Only the creator can update
                Permission.delete(Role.creator()) // Only the creator can delete
            ]
        );
        console.log("File uploaded:", uploadedFile);

        // 4. Get the Preview URL for the Image
        // Note: getFilePreview is synchronous and returns a URL string
        const previewUrl = storage.getFilePreview(
            bucketId,
            uploadedFile.$id,
            800,    // width (optional)
            600,    // height (optional)
            'center', // gravity (optional)
            80,     // quality (optional, 1-100)
            0,      // borderWidth (optional)
            '000000', // borderColor (optional)
            10,     // borderRadius (optional)
            1,      // opacity (optional, 0.0 - 1.0)
            0,      // rotation (optional, 0-360)
            'FFFFFF', // background (optional)
            'webp'  // output format (optional)
        );

        console.log("Preview URL:", previewUrl);

        // You can now use this URL in an <img> tag
        // const img = document.createElement('img');
        // img.src = previewUrl;
        // document.body.appendChild(img);

    } catch (error) {
        console.error("An error occurred:", error);
    }
}

// Example usage: 
// document.getElementById('fileInput').addEventListener('change', (e) => handleImageUpload(e.target));
```

### Key Concepts Explained:

1. **Permissions (`Permission` & `Role`)**: 
   * When creating the bucket, we set base permissions. We allowed anyone (`Role.any()`) to read, but only authenticated users (`Role.users()`) to modify the bucket.
   * When uploading the file, we set file-level permissions. We allowed anyone to read the file, but only the user who uploaded it (`Role.creator()`) to update or delete it.
2. **`InputFile.fromBlob()`**: The Web SDK requires you to wrap the browser's native `File` or `Blob` object using `InputFile.fromBlob()` before passing it to the `createFile` method.
3. **`getFilePreview()`**: This method does **not** return a promise. It synchronously constructs and returns a URL string pointing to Appwrite's image transformation endpoint. Appwrite will only generate the preview image when the URL is actually requested by the browser.
4. **File Security**: If your bucket has `fileSecurity` set to `true` (which is the default when you pass permissions to `createFile`), the file-level permissions override the bucket-level permissions for that specific file.

To subscribe to both database document changes and storage file uploads simultaneously using the Appwrite Web SDK, you can pass an array of channel strings to the `client.subscribe` method. You can then differentiate between the event types inside the callback by checking the `channels` array in the response object.

Here is the code to achieve this:

```javascript
import { Client } from "appwrite";

// 1. Initialize the Appwrite Client
const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1") // Your Appwrite Endpoint
  .setProject("YOUR_PROJECT_ID");              // Your Project ID

const DATABASE_ID = "YOUR_DATABASE_ID";
const COLLECTION_ID = "YOUR_COLLECTION_ID";
const BUCKET_ID = "YOUR_BUCKET_ID";

// 2. Subscribe to both channels simultaneously
const unsubscribe = client.subscribe(
  [
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`, 
    `buckets.${BUCKET_ID}.files`
  ],
  (response) => {
    // Destructure the response object
    const { events, channels, payload } = response;

    // 3. Handle Database Row Changes
    if (channels.includes(`databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`)) {
      // Extract the specific action (e.g., 'create', 'update', 'delete')
      const action = events[0].split(".").pop(); 

      console.log(`📄 Database Event (${action}):`, payload);

      switch (action) {
        case "create":
          console.log("New document created:", payload.$id);
          break;
        case "update":
          console.log("Document updated:", payload.$id);
          break;
        case "delete":
          console.log("Document deleted:", payload.$id);
          break;
      }
    }

    // 4. Handle File Uploads / Changes
    if (channels.includes(`buckets.${BUCKET_ID}.files`)) {
      const action = events[0].split(".").pop();

      console.log(`📁 Storage Event (${action}):`, payload);

      switch (action) {
        case "create":
          console.log("New file uploaded:", payload.$id, payload.name);
          break;
        case "delete":
          console.log("File deleted:", payload.$id);
          break;
        // Note: File updates (like changing permissions) also trigger here
        case "update":
          console.log("File updated:", payload.$id);
          break;
      }
    }
  }
);

// To stop listening to realtime events later:
// unsubscribe();
```

### How it works:
1. **Channels Array**: `client.subscribe` accepts a single string or an array of strings. By providing both the `databases...` and `buckets...` channels, you listen to both simultaneously.
2. **Response Object**: Every time an event fires, the callback receives a `response` containing:
   * `events`: An array of strings representing the exact event triggered (e.g., `databases.X.collections.Y.documents.create`).
   * `channels`: An array of strings representing the channels the event belongs to.
   * `payload`: The actual data of the document or file that triggered the event.
3. **Differentiating Events**: By checking `channels.includes(...)`, you can route the event to the correct handling logic.
4. **Extracting the Action**: Using `events[0].split(".").pop()` is a clean way to extract the specific action (`create`, `update`, or `delete`) from the event string so you can handle them differently within their respective blocks.

You can subscribe to multiple channels by passing an array of strings as the first argument to the `subscribe` method.

Here is the code snippet:

```javascript
client.subscribe(
    [
        'databases.[DATABASE_ID].collections.[COLLECTION_ID].documents',
        'storage.[BUCKET_ID].files'
    ], 
    response => {
        // Callback logic
        console.log(response);
    }
);
```

### The Exact Channel Strings

1.  **TablesDB (Databases) Table Rows:**
    `databases.[DATABASE_ID].collections.[COLLECTION_ID].documents`
    *(Replace `[DATABASE_ID]` with your database ID and `[COLLECTION_ID]` with your table/collection ID.)*

2.  **Storage Bucket Files:**
    `storage.[BUCKET_ID].files`
    *(Replace `[BUCKET_ID]` with your bucket ID.)*

