Make sure your web app’s domain, such as `http://localhost:5173`, is added as a Web Platform in your Appwrite project settings.

```js
import { Client, TablesDB, ID, Permission, Role } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const tablesDB = new TablesDB(client);

const databaseId = "todo_db";
const tableId = "tasks";

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

async function waitForColumn(key) {
  for (let i = 0; i < 30; i++) {
    const column = await tablesDB.getColumn({
      databaseId,
      tableId,
      key,
    });

    if (column.status === "available") return column;

    if (column.status === "failed" || column.status === "stuck") {
