    permissions: [
      Permission.read(Role.any()),
      Permission.create(Role.any()),
    ],
    rowSecurity: false,
    enabled: true,
  });

  // title: varchar/string column
  await tablesDB.createStringColumn({
    databaseId,
    tableId,
    key: "title",
    size: 255,
    required: true,
  });

  // completed: boolean column
  await tablesDB.createBooleanColumn({
    databaseId,
    tableId,
    key: "completed",
    required: false,
    xdefault: false,
  });

  // dueDate: datetime column
  await tablesDB.createDatetimeColumn({
    databaseId,
    tableId,
    key: "dueDate",
    required: false,
  });

  // Columns are created asynchronously, so wait before inserting rows.
  await Promise.all([
    waitForColumn("title"),
    waitForColumn("completed"),
    waitForColumn("dueDate"),
  ]);

  // Insert a row
  const row = await tablesDB.createRow({
    databaseId,
    tableId,
    rowId: ID.unique(),
    data: {
      title: "Finish Appwrite TablesDB example",
      completed: false,
      dueDate: new Date("2026-06-15T12:00:00.000Z").toISOString(),

In TablesDB, you query rows by passing an array of `Query` helpers to `listRows()`. Each `Query.*()` call returns a query string that Appwrite understands.

```js
import { Client, TablesDB, Query } from "appwrite";

const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const tablesDB = new TablesDB(client);

const databaseId = "<DATABASE_ID>";
const tableId = "<TABLE_ID>";
```

## Filtering rows

Multiple queries are combined with `AND`. Multiple values inside `Query.equal()` work like `OR`.

```js
const result = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.equal("status", ["published"]),          // status = published
    Query.equal("category", ["news", "tutorial"]), // category = news OR tutorial
    Query.greaterThanEqual("views", 100),          // views >= 100
    Query.search("title", "Appwrite"),             // full-text search
  ],
});

console.log(result.rows);
```

Other useful filters:

```js
Query.notEqual("status", ["draft"]);
Query.lessThan("price", 100);
Query.between("price", 10, 50);
Query.isNotNull("publishedAt");
Query.startsWith("name", "A");
```

## Sorting rows

Use `Query.orderAsc()` or `Query.orderDesc()`.

```js
const result = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.equal("status", ["published"]),
    Query.orderDesc("$createdAt"),
  ],
});
```

You can sort by your own columns or system columns like:

```js
Query.orderAsc("title");
Query.orderDesc("$createdAt");
Query.orderDesc("$updatedAt");
```

## Limiting results

Use `Query.limit()` to control page size.

```js
const result = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.limit(10),
  ],
});

console.log(result.rows);
```

Appwrite returns a limited number of rows by default, so you should usually set your own limit for pagination.

## Offset pagination

Offset pagination is simple and useful for smaller datasets.

```js
const page = 2;
const perPage = 20;

const result = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.orderDesc("$createdAt"),
    Query.limit(perPage),
    Query.offset((page - 1) * perPage),
  ],
});

console.log(result.rows);
```

## Cursor pagination

Cursor pagination is usually better for large or frequently changing datasets.

```js
const firstPage = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.orderDesc("$createdAt"),
    Query.limit(20),
  ],
});

const lastRow = firstPage.rows[firstPage.rows.length - 1];

const nextPage = await tablesDB.listRows({
  databaseId,
  tableId,
  queries: [
    Query.orderDesc("$createdAt"),
    Query.limit(20),
    Query.cursorAfter(lastRow.$id),
  ],
});

console.log(nextPage.rows);
```

To go backward, use:

```js
Query.cursorBefore(firstRow.$id);
```

## Notes

- Filters and sorting may require indexes on the queried columns.
- `Query.search()` requires a full-text index.
- Results still respect Appwrite permissions.
- Older SDK versions may use positional arguments, but the `queries` array works the same way.

Use Appwrite’s `Query` helpers together in the `queries` array:

```js
import { Query } from 'appwrite';

const result = await tablesDB.listRows({
  databaseId: 'DATABASE_ID',
  tableId: 'TABLE_ID',
  queries: [
    Query.greaterThan('amount', 100),
    Query.orderDesc('amount'),
    Query.limit(20),
  ],
});
```

This does three things:

- `Query.greaterThan('amount', 100)` returns only rows where `amount > 100`
- `Query.orderDesc('amount')` sorts rows by `amount` descending
- `Query.limit(20)` returns at most 20 rows

If you’re using the older Databases API with collections/documents, the same queries apply:

```js
const result = await databases.listDocuments(
  'DATABASE_ID',
  'COLLECTION_ID',
  [
    Query.greaterThan('amount', 100),
    Query.orderDesc('amount'),
    Query.limit(20),
  ]
);
```

Replace `amount` with your numeric field/column name.

```js
// src/main.js

export default async ({ req, res, log, error }) => {
  const body = req.bodyJson || {};
  const name = typeof body.name === 'string' ? body.name.trim() : '';

  if (!name) {
    return res.json(
      { error: 'Missing required JSON field: "name"' },
      400
    );
  }

  return res.json({
    greeting: `Hello, ${name}!`,
  });
};
```

Example request body:

```json
{
  "name": "Alice"
}
```

Example response:

```json
{
  "greeting": "Hello, Alice!"
}
```

You can upload files and generate preview URLs from the Appwrite **Web SDK**, but bucket creation should be done server-side or in the Console because it requires admin/API-key permissions. Do **not** expose an API key in browser code.

## 1. Create the bucket server-side

```js
// create-bucket.js
// Run this once on your server, in a script, or Appwrite Function.

import { Client, Storage, ID, Permission, Role } from "node-appwrite";

const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1")
  .setProject("YOUR_PROJECT_ID")
  .setKey("YOUR_API_KEY"); // Requires buckets.write scope

const storage = new Storage(client);

const bucket = await storage.createBucket(
  "images", // bucketId, or use ID.unique()
  "Images",
  [
    // Allow signed-in users to upload files to this bucket
    Permission.create(Role.users()),
  ],
  true, // fileSecurity: enable per-file permissions
  true, // enabled
  10 * 1024 * 1024, // maximumFileSize: 10 MB
  ["jpg", "jpeg", "png", "gif", "webp"], // allowedFileExtensions
);

console.log(bucket);
```

## 2. Upload an image and get a preview URL in the browser

```js
import { Client, Account, Storage, ID, Permission, Role, ImageGravity } from "appwrite";

const client = new Client()
  .setEndpoint("https://cloud.appwrite.io/v1")
  .setProject("YOUR_PROJECT_ID");

const account = new Account(client);
const storage = new Storage(client);

const BUCKET_ID = "images";

async function uploadImageAndGetPreview(file) {
  // Requires the user to be logged in
  const user = await account.get();

  const uploadedFile = await storage.createFile(
    BUCKET_ID,
    ID.unique(),
    file,
    [
      // Anyone can view the image/preview
      Permission.read(Role.any()),

      // Only the uploader can update/delete it
      Permission.update(Role.user(user.$id)),
      Permission.delete(Role.user(user.$id)),
    ]
  );

  const previewUrl = storage.getFilePreview(
    BUCKET_ID,
    uploadedFile.$id,
    600, // width
    600, // height
    ImageGravity.Center,
    90 // quality
  );

  return previewUrl.toString();
}

// Example with an <input type="file" id="imageInput" />
document.getElementById("imageInput").addEventListener("change", async event => {
  const file = event.target.files[0];
  if (!file) return;

  const previewUrl = await uploadImageAndGetPreview(file);

  console.log("Preview URL:", previewUrl);

  document.getElementById("preview").src = previewUrl;
});
```

Example HTML:

```html
<input id="imageInput" type="file" accept="image/*" />
<img id="preview" alt="Image preview" />
```

If you do not want public image previews, replace:

```js
Permission.read(Role.any())
```

with:

```js
Permission.read(Role.user(user.$id))
```

```js
import { Client } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const databaseId = "<DATABASE_ID>";
const tableId = "<TABLE_ID>";
const bucketId = "<BUCKET_ID>";

const rowChannel = `databases.${databaseId}.tables.${tableId}.rows`;
const fileChannel = `buckets.${bucketId}.files`;

const rowEventPrefix = `databases.${databaseId}.tables.${tableId}.rows.`;
const fileEventPrefix = `buckets.${bucketId}.files.`;

function getAction(events) {
  if (events.some((event) => event.endsWith(".create"))) return "create";
  if (events.some((event) => event.endsWith(".update"))) return "update";
  if (events.some((event) => event.endsWith(".delete"))) return "delete";
  return "unknown";
}

const unsubscribe = client.subscribe(
  [rowChannel, fileChannel],
  (response) => {
    const { events, channels, payload } = response;

    const isRowEvent =
      channels.includes(rowChannel) ||
      events.some((event) => event.startsWith(rowEventPrefix));

    const isFileEvent =
      channels.includes(fileChannel) ||
      events.some((event) => event.startsWith(fileEventPrefix));

    const action = getAction(events);

    if (isRowEvent) {
      switch (action) {
        case "create":
          console.log("Row created:", payload);
          break;

        case "update":
          console.log("Row updated:", payload);
          break;

        case "delete":
          console.log("Row deleted:", payload);
          break;

        default:
          console.log("Other row event:", response);
      }

      return;
    }

    if (isFileEvent) {
      switch (action) {
        case "create":
          console.log("File uploaded:", payload);
          break;

        case "update":
          console.log("File updated:", payload);
          break;

        case "delete":
          console.log("File deleted:", payload);
          break;

        default:
          console.log("Other file event:", response);
      }
    }
  }
);

// Later, when you no longer need realtime updates:
unsubscribe();
```

This uses one realtime subscription for both channels:

```js
[
  `databases.${databaseId}.tables.${tableId}.rows`,
  `buckets.${bucketId}.files`
]
```

File uploads are emitted as Storage `create` events on the bucket files channel. Realtime events are only received for resources the current user has permission to read.

```js
const unsubscribe = realtime.subscribe(
  [
    'databases.<DATABASE_ID>.tables.<TABLE_ID>.rows',
    'buckets.<BUCKET_ID>.files',
  ],
  (response) => {
    console.log(response);
  }
);
```

Exact channel formats:

- TablesDB table rows: `databases.<DATABASE_ID>.tables.<TABLE_ID>.rows`
- Storage bucket files: `buckets.<BUCKET_ID>.files`

Replace the placeholders with your actual IDs, without the angle brackets.

# Appwrite Email/Password Authentication

Here's a complete implementation of email/password signup and login using the Appwrite Web SDK.

## Installation

```bash
npm install appwrite
```

## 1. Setup the Client

Create a file `appwrite.js` to initialize the Appwrite client:

```javascript
// appwrite.js
import { Client, Account, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');            // Your project ID

export const account = new Account(client);
export { ID };
```

## 2. Sign Up (Create Account)

```javascript
// signup.js
import { account, ID } from './appwrite';

async function signUp(email, password, name) {
    try {
        // Create a new user account
        const user = await account.create(
            ID.unique(),  // Unique user ID
            email,
            password,
            name
        );

        console.log('Account created:', user);

        // Automatically log in the user after signup
        await login(email, password);

        return user;
    } catch (error) {
        console.error('Signup failed:', error);
        throw error;
    }
}
```

## 3. Log In (Create Session)

```javascript
// login.js
import { account } from './appwrite';

async function login(email, password) {
    try {
        // Create an email/password session
        const session = await account.createEmailPasswordSession(
            email,
            password
        );

        console.log('Session created:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error);
        throw error;
    }
}
```

## 4. Get Current User & Logout

```javascript
// auth.js
import { account } from './appwrite';

// Get the currently logged-in user
async function getCurrentUser() {
    try {
        const user = await account.get();
        return user;
    } catch (error) {
        console.log('No active session');
        return null;
    }
}

// Log out by deleting the current session
async function logout() {
    try {
        await account.deleteSession('current');
        console.log('Logged out');
    } catch (error) {
        console.error('Logout failed:', error);
    }
}
```

## 5. Complete Example Usage

```javascript
import { account, ID } from './appwrite';

// Sign up a new user
async function handleSignUp() {
    try {
        await account.create(
            ID.unique(),
            'user@example.com',
            'SecurePassword123',
            'John Doe'
        );

        // Create session right after signup
        await account.createEmailPasswordSession(
            'user@example.com',
            'SecurePassword123'
        );

        // Get user details
        const user = await account.get();
        console.log('Logged in as:', user.name);
    } catch (error) {
        console.error(error);
    }
}

// Log in existing user
async function handleLogin() {
    try {
        await account.createEmailPasswordSession(
            'user@example.com',
            'SecurePassword123'
        );

        const user = await account.get();
        console.log('Welcome back,', user.name);
    } catch (error) {
        console.error(error);
    }
}
```

## Key Notes

- **Password requirements**: Minimum 8 characters by default.
- **`ID.unique()`**: Generates a unique user ID. You can also provide your own custom ID.
- **`account.create()`** only creates the account; it does **not** log the user in. You must call `createEmailPasswordSession()` separately.
- **Sessions** are automatically stored by the SDK using cookies (for web apps on the same domain) so subsequent API calls are authenticated.
- Make sure to add your web app's hostname as a **Platform** in your Appwrite project settings to avoid CORS issues.

# Appwrite TablesDB Example

> **Note:** Schema operations (creating databases, tables, and columns) require an API key and must be run server-side. The Web SDK can only perform row-level operations. I'll use `node-appwrite` for setup and show the Web SDK usage for inserting a row.

## 1. Server-side: Create Database, Table, and Columns

```js
import { Client, TablesDB, ID } from "node-appwrite";

const client = new Client()
    .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
    .setProject("<PROJECT_ID>")
    .setKey("<API_KEY>");

const tablesDB = new TablesDB(client);

async function setup() {
    // 1. Create the database
    const database = await tablesDB.create({
        databaseId: "main",
        name: "Main DB",
    });

    // 2. Create the "tasks" table
    const table = await tablesDB.createTable({
        databaseId: database.$id,
        tableId: "tasks",
        name: "Tasks",
    });

    // 3. Create columns
    await tablesDB.createStringColumn({
        databaseId: database.$id,
        tableId: table.$id,
        key: "title",
        size: 255,
        required: true,
    });

    await tablesDB.createBooleanColumn({
        databaseId: database.$id,
        tableId: table.$id,
        key: "completed",
        required: false,
        default: false,
    });

    await tablesDB.createDatetimeColumn({
        databaseId: database.$id,
        tableId: table.$id,
        key: "dueDate",
        required: false,
    });

    console.log("Schema created ✅");
}

setup();
```

## 2. Client-side: Insert a Row with the Web SDK

```js
import { Client, TablesDB, ID } from "appwrite";

const client = new Client()
    .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
    .setProject("<PROJECT_ID>");

const tablesDB = new TablesDB(client);

async function addTask() {
    const row = await tablesDB.createRow({
        databaseId: "main",
        tableId: "tasks",
        rowId: ID.unique(),
        data: {
            title: "Write Appwrite blog post",
            completed: false,
            dueDate: new Date("2025-12-31T23:59:00.000Z").toISOString(),
        },
    });

    console.log("Row created:", row);
}

addTask();
```

### Key points about the TablesDB API
- `TablesDB` replaces the older `Databases` service, with methods renamed around **tables/rows/columns** instead of collections/documents/attributes.
- Methods now accept a **single object of named parameters** (e.g., `{ databaseId, tableId, rowId, data }`) rather than positional arguments.
- Column creation helpers include `createStringColumn`, `createBooleanColumn`, `createDatetimeColumn`, `createIntegerColumn`, `createFloatColumn`, `createEmailColumn`, `createRelationshipColumn`, etc.
- Datetime columns expect ISO 8601 strings.

# Appwrite Function: Personalized Greeting (Node.js)

Here's a complete Appwrite Function that receives a JSON body with a `name` field and returns a personalized greeting:

```javascript
export default async ({ req, res, log, error }) => {
  try {
    // Parse the request body
    // req.bodyJson automatically parses JSON payloads
    const { name } = req.bodyJson ?? {};

    // Validate input
    if (!name || typeof name !== 'string') {
      return res.json(
        {
          success: false,
          message: 'Please provide a valid "name" field in the request body.',
        },
        400
      );
    }

    log(`Generating greeting for: ${name}`);

    // Return a personalized greeting
    return res.json({
      success: true,
      message: `Hello, ${name}! Welcome to Appwrite Functions.`,
    });
  } catch (err) {
    error(`Error processing request: ${err.message}`);
    return res.json(
      {
        success: false,
        message: 'An unexpected error occurred.',
      },
      500
    );
  }
};
```

## Key Points

### Function Signature
Appwrite Node.js functions use a **default export** of an async function that receives a single context object with:
- **`req`** — the request (headers, body, method, path, query)
- **`res`** — used to send responses
- **`log`** — writes to function logs (visible in the Appwrite console)
- **`error`** — writes to error logs

### Request Body Access
- `req.bodyJson` — parsed JSON object (recommended for JSON payloads)
- `req.bodyText` — raw string body
- `req.bodyBinary` — raw binary buffer

### Response Methods
- `res.json(obj, statusCode?, headers?)` — return JSON
- `res.text(str, statusCode?, headers?)` — return plain text
- `res.binary(buffer, statusCode?, headers?)` — return binary data
- `res.empty()` — return empty response
- `res.redirect(url, statusCode?)` — redirect

## Testing the Function

Once deployed, you can test it with `curl`:

```bash
curl -X POST https://<REGION>.cloud.appwrite.io/v1/functions/<FUNCTION_ID>/executions \
  -H "Content-Type: application/json" \
  -H "X-Appwrite-Project: <PROJECT_ID>" \
  -d '{"body": "{\"name\": \"Alice\"}"}'
```

Or directly, if you've enabled execution via a domain:

```bash
curl -X POST https://<FUNCTION_DOMAIN>/ \
  -H "Content-Type: application/json" \
  -d '{"name": "Alice"}'
```

### Expected Response

```json
{
  "success": true,
  "message": "Hello, Alice! Welcome to Appwrite Functions."
}
```

## `package.json`

Make sure your `package.json` specifies the entry point:

```json
{
  "name": "greeting-function",
  "version": "1.0.0",
  "main": "src/main.js",
  "type": "module"
}
```

Then in the Appwrite console, set the **entrypoint** to `src/main.js` and select a Node.js runtime (e.g., `node-18.0` or newer).

# Appwrite Storage: Bucket, Upload & Preview

**Important note:** Bucket creation is a server-side operation and requires an **API key with `buckets.write` scope**. It's only available in the server SDKs (like `node-appwrite`). File uploads and previews can be done with the Web SDK.

## 1. Create a Bucket (Server-side with `node-appwrite`)

```js
import { Client, Storage, Permission, Role, ID } from "node-appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>")
  .setKey("<API_KEY>"); // server-only

const storage = new Storage(client);

const bucket = await storage.createBucket(
  ID.unique(),             // bucketId
  "Images",                // name
  [                        // permissions
    Permission.read(Role.any()),              // public read
    Permission.create(Role.users()),          // any logged-in user can upload
    Permission.update(Role.user("USER_ID")),  // only owner can update
    Permission.delete(Role.user("USER_ID")),  // only owner can delete
  ],
  true,                    // fileSecurity (per-file permissions enabled)
  true,                    // enabled
  30000000,                // maximumFileSize (bytes)
  ["jpg", "jpeg", "png", "webp", "gif"], // allowedFileExtensions
  "none",                  // compression: none | gzip | zstd
  true,                    // encryption
  true                     // antivirus
);

console.log("Bucket:", bucket.$id);
```

## 2. Upload a File + Get Preview URL (Web SDK)

```js
import { Client, Storage, ID, Permission, Role } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const storage = new Storage(client);
const BUCKET_ID = "<BUCKET_ID>";

// HTML: <input type="file" id="uploader" />
const input = document.getElementById("uploader");

input.addEventListener("change", async (e) => {
  const file = e.target.files[0];

  // Upload file with per-file permissions
  const uploaded = await storage.createFile(
    BUCKET_ID,
    ID.unique(),
    file,
    [
      Permission.read(Role.any()),                  // public read
      Permission.update(Role.user("USER_ID")),      // owner can update
      Permission.delete(Role.user("USER_ID")),      // owner can delete
    ]
  );

  console.log("Uploaded:", uploaded.$id);

  // Preview URL (resized/optimized — image files only)
  const previewUrl = storage.getFilePreview(
    BUCKET_ID,
    uploaded.$id,
    400,        // width
    400,        // height
    "center",   // gravity
    85,         // quality (0–100)
    0,          // borderWidth
    "",         // borderColor
    10,         // borderRadius
    1,          // opacity
    0,          // rotation
    "",         // background
    "webp"      // output format
  );

  // Original file URL (any file type)
  const viewUrl = storage.getFileView(BUCKET_ID, uploaded.$id);

  // Forced download URL
  const downloadUrl = storage.getFileDownload(BUCKET_ID, uploaded.$id);

  document.body.insertAdjacentHTML(
    "beforeend",
    `<img src="${previewUrl}" alt="preview" />`
  );
});
```

## Permission Tips

- **Bucket-level permissions** apply to all files unless `fileSecurity: true`.
- With `fileSecurity: true`, Appwrite checks **both** bucket and file permissions — a user needs access at either level.
- Common roles:
  - `Role.any()` — anyone, including guests
  - `Role.users()` — any authenticated user
  - `Role.user(userId)` — a specific user
  - `Role.team(teamId)` — members of a team

## Install

```bash
npm install appwrite        # client (Web)
npm install node-appwrite   # server (bucket creation)
```

```javascript
import { Client } from "appwrite";

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

// Subscribe to multiple channels simultaneously
const unsubscribe = client.subscribe(
    [
        'databases.<DATABASE_ID>.tables.<TABLE_ID>.rows',
        'buckets.<BUCKET_ID>.files'
    ],
    (response) => {
        // Handle table row events
        if (response.channels.some(ch => ch.includes('tables'))) {
            const { events, payload } = response;

            if (events.includes('databases.*.tables.*.rows.*.create')) {
                console.log('Row created:', payload);
            } else if (events.includes('databases.*.tables.*.rows.*.update')) {
                console.log('Row updated:', payload);
            } else if (events.includes('databases.*.tables.*.rows.*.delete')) {
                console.log('Row deleted:', payload);
            }
        }

        // Handle file events
        if (response.channels.some(ch => ch.includes('buckets'))) {
            const { events, payload } = response;

            if (events.includes('buckets.*.files.*.create')) {
                console.log('File uploaded:', payload.name, payload.$id);
            } else if (events.includes('buckets.*.files.*.update')) {
                console.log('File updated:', payload);
            } else if (events.includes('buckets.*.files.*.delete')) {
                console.log('File deleted:', payload.$id);
            }
        }
    }
);

// Later, to close the subscription
// unsubscribe();
```

**Key points:**

- `client.subscribe()` accepts an array of channels, letting you listen to multiple event streams with a single connection.
- Inspect `response.channels` to determine which source the event came from (tables vs. buckets).
- Use `response.events` to match specific action types (`create`, `update`, `delete`) with wildcard patterns.
- The returned function unsubscribes from **all** channels when called — store it to clean up on component unmount.

# Subscribing to a TablesDB Table and a Storage Bucket in One Call

`client.subscribe()` accepts an array of channel strings, so you can listen to both sources with a single subscription:

```js
import { Client, Storage, TablesDB } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const unsubscribe = client.subscribe(
  [
    "databases.<DATABASE_ID>.tables.<TABLE_ID>.rows",
    "buckets.<BUCKET_ID>.files",
  ],
  (response) => {
    if (response.channels.includes("databases.<DATABASE_ID>.tables.<TABLE_ID>.rows")) {
      console.log("Row event:", response.events, response.payload);
    }

    if (response.channels.includes("buckets.<BUCKET_ID>.files")) {
      console.log("File event:", response.events, response.payload);
    }
  }
);
```

## The exact channel strings

| Source | Channel |
|---|---|
| All rows in a table | `databases.[DATABASE_ID].tables.[TABLE_ID].rows` |
| All files in a bucket | `buckets.[BUCKET_ID].files` |

If you want to narrow it down further, you can also subscribe to:

- A specific row: `databases.[DATABASE_ID].tables.[TABLE_ID].rows.[ROW_ID]`
- A specific file: `buckets.[BUCKET_ID].files.[FILE_ID]`

Just replace `[DATABASE_ID]`, `[TABLE_ID]`, `[ROW_ID]`, `[BUCKET_ID]`, and `[FILE_ID]` with your actual IDs.

