Appwrite does not have a "TablesDB" API. It uses the **Databases API** with **Collections** (not tables), **Attributes** (not columns), and **Documents** (not rows).

Here is the current Appwrite Web SDK code:

```javascript
import { Client, Databases, ID } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const databases = new Databases(client);

const DATABASE_ID = 'tasks-db';
const COLLECTION_ID = 'tasks';

async function setupTasks() {
  // 1. Create database
  await databases.create(DATABASE_ID, 'Tasks Database');

  // 2. Create collection (table equivalent)
  await databases.createCollection(DATABASE_ID, COLLECTION_ID, 'Tasks');

  // 3. Create attributes (column equivalents)
  await databases.createStringAttribute(DATABASE_ID, COLLECTION_ID, 'title', 255, true);
  await databases.createBooleanAttribute(DATABASE_ID, COLLECTION_ID, 'completed', true, false);
  await databases.createDatetimeAttribute(DATABASE_ID, COLLECTION_ID, 'dueDate', true);

  // 4. Insert document (row equivalent)
  const task = await databases.createDocument(
    DATABASE_ID,
    COLLECTION_ID,
    ID.unique(),
    {
      title: 'Complete project documentation',
      completed: false,
      dueDate: new Date('2024-12-31T23:59:00.000Z').toISOString()
    }
  );

  return task;
}

setupTasks().then(console.log).catch(console.error);
```

**Note:** Creating databases, collections, and attributes from the Web SDK requires an authenticated user with admin/owner permissions. In production apps, this setup is typically done server-side with the Server SDK and an API key.

Here is an Appwrite Function for Node.js using the **1.4+ runtime signature** (`context` destructured into `{ req, res, log, error }`):

```javascript
export default async ({ req, res, log, error }) => {
  try {
    // Appwrite auto-parses JSON bodies, but fall back to manual parsing if needed
    const body = typeof req.body === 'string' ? JSON.parse(req.body) : req.body;
    const name = body?.name;

    if (!name) {
      return res.json(
        { success: false, message: 'Missing "name" field in JSON body' },
        400
      );
    }

    log(`Generating greeting for: ${name}`);

    return res.json({
      success: true,
      greeting: `Hello, ${name}!`
    });
  } catch (err) {
    error(err);
    return res.json(
      { success: false, message: 'Invalid request body' },
      400
    );
  }
};
```

### Key details
- **Signature:** The handler receives `{ req, res, log, error }`.
- **Body access:** Use `req.body`. The runtime automatically parses JSON when the `Content-Type: application/json` header is present, but the code defensively handles a raw string fallback.
- **Response:** Always `return` the response object. `res.json(body, statusCode)` sends a JSON response; omit the status code to default to `200`.
- **Logging:** Use `log()` for info and `error()` for errors—these appear in the Appwrite Console execution logs.

```javascript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// 1. Initialize Client
const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')  // Your API endpoint
  .setProject('<PROJECT_ID>');                  // Your project ID

const storage = new Storage(client);

async function createBucketUploadAndPreview(file) {
  try {
    // 2. Create a new bucket with permissions
    const bucket = await storage.createBucket(
      ID.unique(),                  // bucketId
      'Image Bucket',               // name
      [
        Permission.read(Role.any()),     // Anyone can view/download
        Permission.create(Role.users())  // Only authenticated users can upload
      ],
      true,   // fileSecurity (enable file-level permissions)
      true    // enabled
    );

    // 3. Upload an image file to the bucket
    // 'file' should be a File object (e.g., from <input type="file">)
    const uploadedFile = await storage.createFile(
      bucket.$id,
      ID.unique(),          // fileId
      file,
      [
        Permission.read(Role.any()),      // Public read for this file
        Permission.delete(Role.users())   // Authenticated users can delete
      ]
    );

    // 4. Get a preview URL for the image
    // This is a synchronous URL builder you can use directly in an <img> tag
    const previewUrl = storage.getFilePreview(
      bucket.$id,
      uploadedFile.$id,
      800,       // width (optional)
      600,       // height (optional)
      'center',  // gravity (optional)
      80         // quality (optional)
    );

    console.log('Preview URL:', previewUrl);
    return { bucket, file: uploadedFile, previewUrl };

  } catch (error) {
    console.error('Storage error:', error);
    throw error;
  }
}

// Example usage with a file input
document.getElementById('fileInput').addEventListener('change', async (e) => {
  const file = e.target.files[0];
  if (file && file.type.startsWith('image/')) {
    const { previewUrl } = await createBucketUploadAndPreview(file);
    document.getElementById('previewImg').src = previewUrl;
  }
});
```

**HTML**
```html
<input type="file" id="fileInput" accept="image/*" />
<img id="previewImg" alt="Preview" />
```

**Key details**
- **Permissions**: `Role.any()` allows guest access; `Role.users()` restricts to authenticated sessions. `Permission.create` on the bucket controls who can upload, while `Permission.read` on the file controls who can view the preview.
- **fileSecurity**: Set to `true` so individual files can have their own permission rules.
- **getFilePreview**: Returns a URL string (not a Promise) that includes your project ID and any image transformation parameters.

```javascript
import { Client } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your API endpoint
  .setProject('YOUR_PROJECT_ID');

// Pass an array of channels to listen to both sources at once
const unsubscribe = client.subscribe([
  'databases.YOUR_DATABASE_ID.collections.YOUR_COLLECTION_ID.documents',
  'buckets.YOUR_BUCKET_ID.files'
], (response) => {
  // Determine the source from the channels the message was broadcast on
  const isDatabaseEvent = response.channels.some(ch => ch.startsWith('databases.'));
  const isStorageEvent  = response.channels.some(ch => ch.startsWith('buckets.'));

  if (isDatabaseEvent) {
    const document = response.payload;

    if (response.events.some(e => e.endsWith('.create'))) {
      console.log('Row created:', document.$id, document);
    } else if (response.events.some(e => e.endsWith('.update'))) {
      console.log('Row updated:', document.$id, document);
    } else if (response.events.some(e => e.endsWith('.delete'))) {
      console.log('Row deleted:', document.$id);
    }
  } 
  else if (isStorageEvent) {
    const file = response.payload;

