Here's the current way to create a database, table with columns, and insert a row using the **Appwrite Web SDK (TablesDB)**:

```javascript
import { Client, TablesDB, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('YOUR_PROJECT_ID');              // Replace with your project ID

const tablesDB = new TablesDB(client);

async function setupTasksTable() {
    try {
        // 1. Create Database
        const database = await tablesDB.createDatabase(
            ID.unique(),
            'Tasks Database'
        );

        // 2. Create Table
        const table = await tablesDB.createTable(
            database.$id,
            ID.unique(),
            'tasks'
        );

        // 3. Create Columns
        await tablesDB.createStringColumn(
            database.$id,
            table.$id,
            'title',
            255,      // max length
            true,     // required
            '',       // default value
            false     // array
        );

        await tablesDB.createBooleanColumn(
            database.$id,
            table.$id,
            'completed',
            true,     // required
            false     // default value
        );

        await tablesDB.createDatetimeColumn(
            database.$id,
            table.$id,
            'dueDate',
            false,    // not required
            ''        // default value
        );

        // 4. Insert a Row
        const row = await tablesDB.createRow(
            database.$id,
            table.$id,
            ID.unique(),
            {
                title: 'Finish project documentation',
                completed: false,
                dueDate: '2025-06-15T17:00:00.000Z' // ISO 8601 format
            }
        );

        console.log('Row created:', row);
        return { database, table, row };

    } catch (error) {
        console.error('Error setting up tasks table:', error);
    }
}

// Run the setup
setupTasksTable();
```

### Key Notes:

- Use `ID.unique()` for auto-generated IDs.
- Column types use specific methods: `createStringColumn`, `createBooleanColumn`, `createDatetimeColumn`, etc.
- Datetime values must be in **ISO 8601** format (e.g., `2025-06-15T17:00:00.000Z`).
- You must create the database and table **before** adding columns.
- In production, consider adding proper error handling and checking if resources already exist.

**To filter documents where a numeric field is greater than 100, limit the results to 20, and sort them descending by that field, use the following `Query` methods:**

### Required Queries

```js
import { Query } from 'appwrite';

const queries = [
  Query.greaterThan('numericField', 100),   // Filter
  Query.orderDesc('numericField'),          // Sort descending
  Query.limit(20)                           // Limit results
];
```

### Full Example (JavaScript SDK)

```js
import { Client, Databases, Query } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')
  .setProject('YOUR_PROJECT_ID');

const databases = new Databases(client);

const result = await databases.listDocuments(
  'DATABASE_ID',
  'COLLECTION_ID',
  [
    Query.greaterThan('numericField', 100),
    Query.orderDesc('numericField'),
    Query.limit(20)
  ]
);

console.log(result.documents);
```

### Key Points

- `Query.greaterThan('field', 100)` — filters documents where the field value > 100.
- `Query.orderDesc('field')` — sorts results in descending order by the same field.
- `Query.limit(20)` — restricts the response to a maximum of 20 documents.
- You can combine these queries in any order inside the array.
- The same `Query` methods work across all Appwrite SDKs (JavaScript, Python, PHP, Dart, etc.).

**Tip:** If you also need pagination, add `Query.cursorAfter(...)` or `Query.cursorBefore(...)` instead of (or in addition to) `limit`.

```javascript
module.exports = async (req, res) => {
  const name = req.body?.name || 'World';

  res.json({
    message: `Hello, ${name}!`
  });
};
```

### Key Points:

- **Function signature**: Use `module.exports = async (req, res) => { ... }`
- **Request body**: Access the parsed JSON via `req.body`
- **Response**: Use `res.json()` to return a JSON response (recommended for Appwrite Functions)
- **Safety**: Used optional chaining (`?.`) and a fallback value in case `name` is missing

### Alternative (with error handling):

```javascript
module.exports = async (req, res) => {
  try {
    const { name } = req.body || {};

    if (!name) {
      return res.json({ error: 'Name is required' }, 400);
    }

    res.json({
      message: `Hello, ${name}!`
    });
  } catch (error) {
    res.json({ error: 'Invalid request' }, 400);
  }
};
```

**Here's a complete example** using the Appwrite Web SDK (v13+):

```javascript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Initialize Appwrite
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('YOUR_PROJECT_ID');               // Replace with your project ID

const storage = new Storage(client);

// ============================================
// 1. Create a Bucket with Permissions
// ============================================
async function createImageBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),                    // bucketId
            'Images',                       // name
            [
                Permission.read(Role.any()),           // Public read
                Permission.write(Role.users()),        // Authenticated users can write
            ],
            true,                           // fileSecurity: true (files can have own permissions)
            true,                           // enabled
            10 * 1024 * 1024,               // max 10MB
            ['jpg', 'jpeg', 'png', 'webp', 'gif']
        );

        console.log('Bucket created:', bucket.$id);
        return bucket.$id;
    } catch (error) {
        console.error('Failed to create bucket:', error);
        throw error;
    }
}

// ============================================
// 2. Upload File with Permissions
// ============================================
async function uploadImage(bucketId, file) {
    try {
        const uploadedFile = await storage.createFile(
            bucketId,
            ID.unique(),
            file,
            [
                Permission.read(Role.any()),                    // Public preview
                Permission.write(Role.user('[USER_ID]')),       // Only uploader can modify/delete
                // Permission.write(Role.users()),              // Alternative: all authenticated users
            ]
        );

        console.log('File uploaded:', uploadedFile.$id);
        return uploadedFile.$id;
    } catch (error) {
        console.error('Upload failed:', error);
        throw error;
    }
}

// ============================================
// 3. Get Image Preview URL
// ============================================
function getImagePreview(bucketId, fileId, width = 800, height = 800) {
    return storage.getFilePreview(
        bucketId,
        fileId,
        width,                    // width
        height,                   // height
        'center',                 // gravity
        85,                       // quality (0-100)
        0,                        // borderWidth
        '000000',                 // borderColor
        0,                        // borderRadius
        0,                        // opacity
        0,                        // rotation
        'jpg'                     // output format
    );
}

// ============================================
// Usage Example
// ============================================
async function main() {
    // 1. Create bucket (usually done once via console or admin)
    const bucketId = await createImageBucket();

    // 2. Get file from input
    const fileInput = document.getElementById('fileInput');
    const file = fileInput.files[0];

    if (!file) {
        alert('Please select a file');
        return;
    }

    // 3. Upload
    const fileId = await uploadImage(bucketId, file);

    // 4. Get preview URL
    const previewUrl = getImagePreview(bucketId, fileId, 600, 600);

    console.log('Preview URL:', previewUrl);

    // Use it in an image tag
    const img = document.createElement('img');
    img.src = previewUrl;
    document.body.appendChild(img);
}

// Run example
// main();
```

### Key Points:

- **Permissions**: Uses `Permission.read/write(Role.any() / Role.users() / Role.user(id))`
- **fileSecurity: true** → Allows per-file permissions (recommended)
- **Preview URL** is generated client-side and works immediately for public files
- Replace `YOUR_PROJECT_ID` and the endpoint with your values

